('verbal', 'Paintbrush is to painter as scalpel is to:', NULL, '["Hospital", "Surgeon", "Nurse", "Patient"]'::jsonb, 1, 2, 'A paintbrush is the primary tool of a painter; a scalpel is the primary tool of a surgeon.'),
('verbal', 'Which word does NOT belong with the others?', NULL, '["Hammer", "Wrench", "Screwdriver", "Paintbrush"]'::jsonb, 3, 2, 'Hammer, wrench, screwdriver are repair tools; paintbrush is an art tool.'),
('verbal', 'ELOQUENT most nearly means:', NULL, '["Loud", "Articulate", "Confused", "Brief"]'::jsonb, 1, 2, 'Eloquent means expressing ideas fluently and persuasively.'),
