('verbal', 'Sycophant is to flattery as martyr is to:', NULL, '["Religion", "Sacrifice", "Courage", "Victory"]'::jsonb, 1, 3, 'A sycophant is defined by flattery; a martyr is defined by sacrifice.'),
('verbal', 'LOQUACIOUS most nearly means:', NULL, '["Silent", "Logical", "Talkative", "Lazy"]'::jsonb, 2, 3, 'Loquacious means tending to talk a great deal.'),
('verbal', 'No reptiles are warm-blooded. Some egg-layers are warm-blooded. Some egg-layers are reptiles — true, false, or uncertain?', NULL, '["True", "False", "Uncertain", "Impossible"]'::jsonb, 2, 3, 'Reptiles lay eggs, but whether warm-blooded egg-layers overlap with reptiles cannot be determined.'),
('verbal', 'BOLD most nearly means:', NULL, '["Timid", "Brave", "Quiet", "Tired"]'::jsonb, 1, 1, 'Bold means showing courage or confidence, just like brave.'),
