('verbal', 'Pen is to writer as brush is to:', NULL, '["Canvas", "Painter", "Paint", "Museum"]'::jsonb, 1, 1, 'A pen is the tool a writer uses; a brush is the tool a painter uses.'),
('verbal', 'Puppy is to dog as kitten is to:', NULL, '["Lion", "Fur", "Cat", "Paw"]'::jsonb, 2, 1, 'A puppy is a young dog; a kitten is a young cat.'),
