('verbal', 'Doctor is to hospital as chef is to:', NULL, '["Food", "Recipe", "Kitchen", "Restaurant"]'::jsonb, 3, 1, 'A doctor works in a hospital; a chef works in a restaurant.'),
('verbal', 'Cub is to bear as lamb is to:', NULL, '["Goat", "Wool", "Sheep", "Farm"]'::jsonb, 2, 1, 'A cub is a young bear; a lamb is a young sheep.'),
('verbal', 'Scissors is to cut as needle is to:', NULL, '["Thread", "Sew", "Knit", "Pin"]'::jsonb, 1, 1, 'Scissors are used to cut; a needle is used to sew.'),
('verbal', 'Floor is to ceiling as ground is to:', NULL, '["Dirt", "Earth", "Sky", "Roof"]'::jsonb, 2, 1, 'The floor is the bottom surface and the ceiling is the top — just as the ground is the bottom and the sky is the top.'),
('verbal', 'Bark is to tree as skin is to:', NULL, '["Hair", "Body", "Animal", "Fur"]'::jsonb, 1, 1, 'Bark is the outer covering of a tree; skin is the outer covering of the human body.'),
('verbal', 'Sad is to cry as funny is to:', NULL, '["Joke", "Smile", "Laugh", "Play"]'::jsonb, 2, 1, 'Feeling sad makes you cry; finding something funny makes you laugh.'),
('verbal', 'Chapter is to book as scene is to:', NULL, '["Actor", "Play", "Movie", "Stage"]'::jsonb, 2, 1, 'A chapter is a section of a book; a scene is a section of a movie.'),
('verbal', 'Mouth is to speak as ear is to:', NULL, '["Sound", "Head", "Hear", "Listen"]'::jsonb, 2, 1, 'The mouth is used to speak; the ear is used to hear.'),
('verbal', 'All birds have wings. A penguin is a bird. A penguin has wings — true, false, or uncertain?', NULL, '["True", "False", "Uncertain", "Impossible"]'::jsonb, 0, 1, 'Since all birds have wings and a penguin is a bird, a penguin must have wings. True.'),
('verbal', 'All squares are rectangles. Shape X is a square. Shape X is a rectangle — true, false, or uncertain?', NULL, '["True", "False", "Uncertain", "Maybe"]'::jsonb, 0, 1, 'Since all squares are rectangles and X is a square, X must be a rectangle. True.'),
('verbal', 'No fish can climb trees. Goldie is a fish. Goldie can climb trees — true, false, or uncertain?', NULL, '["True", "False", "Uncertain", "Maybe"]'::jsonb, 1, 1, 'Since no fish can climb trees and Goldie is a fish, Goldie definitely cannot climb trees. False.'),
('verbal', 'All dogs bark. Rex is a dog. Rex barks — true, false, or uncertain?', NULL, '["True", "False", "Uncertain", "Neither"]'::jsonb, 0, 1, 'All dogs bark; Rex is a dog; therefore Rex barks. True.'),
('verbal', 'Some students like math. Maria is a student. Maria likes math — true, false, or uncertain?', NULL, '["True", "False", "Uncertain", "Neither"]'::jsonb, 2, 1, 'Only some students like math, so we cannot be sure about Maria specifically. Uncertain.'),
('verbal', 'All roses are flowers. All flowers need water. All roses need water — true, false, or uncertain?', NULL, '["True", "False", "Uncertain", "Impossible"]'::jsonb, 0, 1, 'Roses → flowers → need water. By syllogism, roses need water. True.'),
('verbal', 'Which word does NOT belong with the others?', NULL, '["Apple", "Banana", "Carrot", "Grape"]'::jsonb, 2, 1, 'Apple, banana, and grape are fruits; carrot is a vegetable.'),
('verbal', 'Which word does NOT belong with the others?', NULL, '["Shirt", "Pants", "Hat", "Shoes"]'::jsonb, 3, 1, 'Shirt, pants, and hat are clothing worn on the body''s trunk or head; shoes are footwear — different category.'),
('verbal', 'Which word does NOT belong with the others?', NULL, '["Robin", "Sparrow", "Eagle", "Salmon"]'::jsonb, 3, 1, 'Robin, sparrow, and eagle are birds; salmon is a fish.'),
('verbal', 'Which word does NOT belong with the others?', NULL, '["Circle", "Square", "Triangle", "Cube"]'::jsonb, 3, 1, 'Circle, square, and triangle are 2-D shapes; a cube is a 3-D solid.'),
('verbal', 'CANDID most nearly means:', NULL, '["Secret", "Honest", "Polite", "Careful"]'::jsonb, 1, 2, 'Candid means truthful and straightforward — the same as honest.'),
('verbal', 'RESILIENT most nearly means:', NULL, '["Flexible", "Stubborn", "Able to recover", "Fragile"]'::jsonb, 2, 2, 'Resilient means able to bounce back after difficulty — recovering quickly from setbacks.'),
('verbal', 'SCRUTINIZE most nearly means:', NULL, '["Ignore", "Examine carefully", "Clean thoroughly", "Criticize"]'::jsonb, 1, 2, 'To scrutinize means to look at something very closely and carefully.'),
('verbal', 'VIVID most nearly means:', NULL, '["Dull", "Alive", "Bright and clear", "Colorful"]'::jsonb, 2, 2, 'Vivid means producing strong, clear images — bright and clear is the best match.'),
('verbal', 'NOVEL most nearly means:', NULL, '["Old", "Fictional", "New and original", "Long"]'::jsonb, 2, 2, 'As an adjective, novel means new and original or unusual.'),
('verbal', 'DILIGENT most nearly means:', NULL, '["Lazy", "Hardworking", "Clever", "Loyal"]'::jsonb, 1, 2, 'Diligent means working hard and carefully over time.'),
('verbal', 'DUBIOUS most nearly means:', NULL, '["Certain", "Doubtful", "Dangerous", "Clever"]'::jsonb, 1, 2, 'Dubious means feeling uncertain or doubtful about something.'),
('verbal', 'TRANQUIL most nearly means:', NULL, '["Noisy", "Boring", "Peaceful", "Slow"]'::jsonb, 2, 2, 'Tranquil means free from disturbance — calm and peaceful.'),
('verbal', 'HINDER most nearly means:', NULL, '["Help", "Slow down", "Hide", "Follow"]'::jsonb, 1, 2, 'To hinder means to make it harder for something to happen — to slow it down or block it.'),
('verbal', 'FRUGAL most nearly means:', NULL, '["Generous", "Wasteful", "Thrifty", "Greedy"]'::jsonb, 2, 2, 'Frugal means being careful about spending money — the same as thrifty.'),
('verbal', 'AMIABLE most nearly means:', NULL, '["Hostile", "Friendly", "Capable", "Admirable"]'::jsonb, 1, 2, 'Amiable means having a pleasant and friendly manner.'),
('verbal', 'BENEVOLENT most nearly means:', NULL, '["Harmful", "Selfish", "Kind-hearted", "Powerful"]'::jsonb, 2, 2, 'Benevolent means well-meaning and kind toward others.'),
('verbal', 'PONDER most nearly means:', NULL, '["Wonder", "Think deeply about", "Disagree", "Measure"]'::jsonb, 1, 2, 'To ponder means to think about something carefully and for a long time.'),
('verbal', 'PLACID most nearly means:', NULL, '["Upset", "Flat", "Calm", "Pleased"]'::jsonb, 2, 2, 'Placid means not easily upset — calm and peaceful in nature.'),
('verbal', 'METICULOUS most nearly means:', NULL, '["Careless", "Paying great attention to detail", "Slow", "Strict"]'::jsonb, 1, 2, 'Meticulous means giving careful attention to every small detail.'),
('verbal', 'ABUNDANT is the opposite of:', NULL, '["Plentiful", "Scarce", "Expensive", "Common"]'::jsonb, 1, 2, 'Abundant means more than enough; scarce means in very short supply — opposites.'),
('verbal', 'TRANSPARENT is the opposite of:', NULL, '["Clear", "Shiny", "Opaque", "Fragile"]'::jsonb, 2, 2, 'Transparent allows light through; opaque blocks light — they are opposites.'),
('verbal', 'ARROGANT is the opposite of:', NULL, '["Proud", "Humble", "Rude", "Ignorant"]'::jsonb, 1, 2, 'Arrogant means having an exaggerated sense of importance; humble means modest — opposites.'),
('verbal', 'COMPULSORY is the opposite of:', NULL, '["Required", "Forced", "Optional", "Strict"]'::jsonb, 2, 2, 'Compulsory means required by law or rule; optional means left to personal choice.'),
('verbal', 'TRIVIAL is the opposite of:', NULL, '["Minor", "Important", "Boring", "Simple"]'::jsonb, 1, 2, 'Trivial means of little importance; important means of great significance — opposites.'),
('verbal', 'CONCEAL is the opposite of:', NULL, '["Hide", "Cover", "Reveal", "Protect"]'::jsonb, 2, 2, 'To conceal means to hide; to reveal means to make known — opposites.'),
('verbal', 'TIMID is the opposite of:', NULL, '["Shy", "Bold", "Nervous", "Gentle"]'::jsonb, 1, 2, 'Timid means lacking confidence or courage; bold means confident and brave.'),
('verbal', 'HUMBLE is the opposite of:', NULL, '["Modest", "Quiet", "Arrogant", "Simple"]'::jsonb, 2, 2, 'Humble means having a modest view of one''s own importance; arrogant means having an exaggerated sense of superiority — opposites.'),
('verbal', 'PROLONG is the opposite of:', NULL, '["Extend", "Shorten", "Delay", "Continue"]'::jsonb, 1, 2, 'To prolong means to make longer; to shorten means to make shorter — direct opposites.'),
('verbal', 'HOSTILE is the opposite of:', NULL, '["Unfriendly", "Aggressive", "Welcoming", "Angry"]'::jsonb, 2, 2, 'Hostile means showing opposition or aggression; welcoming means friendly and open.'),
('verbal', 'PESSIMISTIC is the opposite of:', NULL, '["Gloomy", "Optimistic", "Realistic", "Negative"]'::jsonb, 1, 2, 'Pessimistic means expecting the worst; optimistic means expecting the best — opposites.'),
('verbal', 'INFERIOR is the opposite of:', NULL, '["Lower", "Worse", "Superior", "Secondary"]'::jsonb, 2, 2, 'Inferior means lower in rank or quality; superior means higher in rank or quality.'),
