('verbal', 'MEAGER is the opposite of:', NULL, '["Thin", "Scarce", "Abundant", "Weak"]'::jsonb, 2, 2, 'Meager means very little or insufficient; abundant means more than enough — opposites.'),
('verbal', 'Warmth is to comfort as cold is to:', NULL, '["Snow", "Discomfort", "Winter", "Ice"]'::jsonb, 1, 2, 'Warmth produces comfort; cold produces discomfort — the same cause-and-effect relationship.'),
('verbal', 'Author is to novel as composer is to:', NULL, '["Piano", "Concert", "Symphony", "Musician"]'::jsonb, 2, 2, 'An author creates a novel; a composer creates a symphony.'),
