('verbal', 'Petal is to flower as feather is to:', NULL, '["Pillow", "Nest", "Wing", "Bird"]'::jsonb, 3, 2, 'A petal is a part of a flower; a feather is a part of a bird.'),
('verbal', 'General is to army as captain is to:', NULL, '["Soldier", "Ship", "Rank", "Battle"]'::jsonb, 1, 2, 'A general commands an army; a captain commands a ship.'),
('verbal', 'Rehearsal is to performance as practice is to:', NULL, '["Sport", "Game", "Training", "Skill"]'::jsonb, 1, 2, 'A rehearsal prepares you for a performance; practice prepares you for a game.'),
('verbal', 'Degree is to temperature as pound is to:', NULL, '["Money", "Weight", "Force", "Volume"]'::jsonb, 1, 2, 'A degree is a unit for measuring temperature; a pound is a unit for measuring weight.'),
