('math', 'Maria earns $12 per hour. She worked 35 hours. She spent $200 on groceries. How much does she have left?', NULL, '["$200", "$220", "$230", "$240"]'::jsonb, 1, 2, '12 × 35 = $420; $420 − $200 = $220.'),
