('math', 'A $200 TV is on sale for 15% off. What is the sale price?', NULL, '["$160", "$165", "$170", "$175"]'::jsonb, 2, 2, '15% of 200 = 30; 200 − 30 = $170.'),
('math', 'What is 2/3 ÷ 4?', NULL, '["1/4", "1/6", "2/12", "8/3"]'::jsonb, 1, 2, '2/3 ÷ 4 = 2/3 × 1/4 = 2/12 = 1/6.'),
('math', 'A test has 40 questions. A student answers 34 correctly. What percent is correct?', NULL, '["80%", "82%", "85%", "88%"]'::jsonb, 2, 2, '34/40 × 100 = 85%.'),
('math', 'What is 5/6 + 2/3?', NULL, '["7/9", "7/6", "3/2", "9/6"]'::jsonb, 2, 2, '2/3 = 4/6; 5/6 + 4/6 = 9/6 = 3/2.'),
('math', 'A price increased from $80 to $100. What is the percent increase?', NULL, '["20%", "22%", "25%", "30%"]'::jsonb, 2, 2, 'Increase = 20; percent = 20/80 × 100 = 25%.'),
('math', 'What is 3/8 as a decimal?', NULL, '["0.3", "0.35", "0.375", "0.38"]'::jsonb, 2, 2, '3 ÷ 8 = 0.375.'),
('math', 'A student got 18 out of 24 problems correct. What percent is this?', NULL, '["70%", "72%", "75%", "80%"]'::jsonb, 2, 2, '18/24 × 100 = 75%.'),
('math', 'What is 4/5 − 1/3?', NULL, '["3/2", "7/15", "4/15", "7/8"]'::jsonb, 1, 2, 'LCD = 15: 12/15 − 5/15 = 7/15.'),
('math', 'What is 40% of 150?', NULL, '["40", "55", "60", "75"]'::jsonb, 2, 2, '0.40 × 150 = 60.'),
('math', 'A number is increased by 30% to get 91. What was the original number?', NULL, '["60", "65", "70", "75"]'::jsonb, 2, 2, 'n × 1.30 = 91 → n = 91 ÷ 1.30 = 70.'),
('math', 'Find the mean of: 5, 10, 15, 20, 25.', NULL, '["10", "13", "15", "20"]'::jsonb, 2, 1, 'Sum = 75; 75 ÷ 5 = 15.'),
('math', 'Find the median of: 7, 3, 9, 1, 5, 11, 6.', NULL, '["5", "6", "7", "9"]'::jsonb, 1, 1, 'Ordered: 1,3,5,6,7,9,11. Median is 4th value = 6.'),
('math', 'A data set has values: 4, 7, 7, 8, 9, 12. What is the mode?', NULL, '["4", "7", "8", "9"]'::jsonb, 1, 1, '7 appears twice; all others appear once. Mode = 7.'),
('math', 'Find the range of: 14, 6, 22, 9, 18, 3.', NULL, '["16", "18", "19", "20"]'::jsonb, 2, 1, 'Range = 22 − 3 = 19.'),
('math', 'Five quiz scores are 72, 85, 90, 68, 80. What is the mean?', NULL, '["77", "79", "80", "83"]'::jsonb, 1, 1, 'Sum = 395; 395 ÷ 5 = 79.'),
('math', 'What is the LCM of 12, 15, and 20?', NULL, '["30", "45", "60", "120"]'::jsonb, 2, 3, '12=2²×3; 15=3×5; 20=2²×5. LCM = 2²×3×5 = 60.'),
('math', 'Evaluate: 2 + 3 × (4² − 6) ÷ 5', NULL, '["6", "7", "8", "9"]'::jsonb, 2, 3, '4² = 16; 16 − 6 = 10; 10 ÷ 5 = 2; 3 × 2 = 6; 2 + 6 = 8.'),
('math', 'What is the GCF of 84, 126, and 210?', NULL, '["14", "21", "42", "63"]'::jsonb, 2, 3, '84=2²×3×7; 126=2×3²×7; 210=2×3×5×7. GCF = 2×3×7 = 42.'),
('math', 'Evaluate: |−14| − |−6| + |−3|', NULL, '["5", "11", "17", "23"]'::jsonb, 1, 3, '14 − 6 + 3 = 11.'),
('math', 'Evaluate: 3³ × 2² − 4 × (6 − 2)', NULL, '["88", "92", "96", "100"]'::jsonb, 1, 3, '3³=27; 2²=4; 27×4=108; 6−2=4; 4×4=16; 108−16=92.'),
('math', 'What is the remainder when 253 is divided by 15?', NULL, '["7", "8", "10", "13"]'::jsonb, 3, 3, '15 × 16 = 240; 253 − 240 = 13. Remainder = 13.'),
('math', 'Evaluate: (2³ + 3²) × (4 − 1) ÷ 3', NULL, '["15", "17", "21", "51"]'::jsonb, 1, 3, '2³=8; 3²=9; 8+9=17; (4−1)=3; 17×3=51; 51÷3=17.'),
('math', 'What is the LCM of 8, 12, and 18?', NULL, '["36", "48", "72", "144"]'::jsonb, 2, 3, '8=2³; 12=2²×3; 18=2×3². LCM = 2³×3² = 72.'),
('math', 'Evaluate: 5! ÷ 3! (where n! means n-factorial)', NULL, '["10", "15", "20", "25"]'::jsonb, 2, 3, '5! = 120; 3! = 6; 120 ÷ 6 = 20.'),
('math', 'Which of these is divisible by both 6 and 8?', NULL, '["42", "48", "54", "64"]'::jsonb, 1, 3, '48 ÷ 6 = 8 ✓; 48 ÷ 8 = 6 ✓. 48 is divisible by both.'),
('math', 'What is 2¹⁰?', NULL, '["256", "512", "1000", "1024"]'::jsonb, 3, 3, '2¹⁰ = 1024.'),
('math', 'Evaluate: √(25 × 36)', NULL, '["25", "30", "36", "61"]'::jsonb, 1, 3, '25 × 36 = 900; √900 = 30.'),
('math', 'What is the remainder when 5¹⁰⁰ is divided by 4?', NULL, '["0", "1", "2", "3"]'::jsonb, 1, 3, '5 = 4 + 1, so 5^n ≡ 1^n = 1 (mod 4). Remainder = 1.'),
('math', 'Evaluate: 4 + 3 × [2 × (5 + 1) − 4]', NULL, '["22", "28", "32", "40"]'::jsonb, 1, 3, '5+1=6; 2×6=12; 12−4=8; 3×8=24; 4+24=28.'),
('math', 'Solve the system: 3x + 2y = 20 and x − y = 5. What is x?', NULL, '["5", "6", "7", "8"]'::jsonb, 1, 3, 'From 2nd: x=y+5. Sub: 3(y+5)+2y=20 → 3y+15+2y=20 → 5y=5 → y=1; x=6.'),
('math', 'Solve the system: x + 2y = 11 and 3x − y = 5. What is y?', NULL, '["2", "3", "4", "5"]'::jsonb, 2, 3, 'From 1st: x = 11−2y. Sub: 3(11−2y)−y=5 → 33−6y−y=5 → 28=7y → y=4. Check: x=11−8=3; 3(3)−4=5 ✓.'),
('math', 'The sum of three consecutive integers is 102. What is the middle integer?', NULL, '["32", "33", "34", "35"]'::jsonb, 2, 3, '(n−1)+n+(n+1)=102 → 3n=102 → n=34.'),
('math', 'If x² − 7x + 12 = 0, what are the values of x?', NULL, '["2 and 6", "3 and 4", "1 and 12", "4 and 6"]'::jsonb, 1, 3, 'Factor: (x−3)(x−4)=0 → x=3 or x=4.'),
('math', 'A number is 5 less than twice another. Their sum is 22. What is the larger number?', NULL, '["9", "11", "13", "15"]'::jsonb, 2, 3, 'Let a = 2b−5; a+b=22 → (2b−5)+b=22 → 3b=27 → b=9; a=13.'),
('math', 'Solve the system: 3x + 2y = 18 and x − y = 1. What is x?', NULL, '["3", "4", "5", "6"]'::jsonb, 1, 3, 'x=y+1; sub: 3(y+1)+2y=18 → 5y+3=18 → y=3; x=4.'),
('math', 'If x² + 5x + 6 = 0, what are the values of x?', NULL, '["\u22122 and \u22123", "2 and 3", "1 and 6", "\u22121 and \u22126"]'::jsonb, 0, 3, 'Factor: (x+2)(x+3)=0 → x=−2 or x=−3.'),
('math', 'The sum of four consecutive integers is 74. What is the smallest?', NULL, '["16", "17", "18", "19"]'::jsonb, 1, 3, 'n+(n+1)+(n+2)+(n+3)=74 → 4n+6=74 → 4n=68 → n=17.'),
('math', 'Solve the system: 2x − y = 3 and x + 2y = 14. What is y?', NULL, '["4", "5", "6", "7"]'::jsonb, 1, 3, 'From 1st: y=2x−3. Sub: x+2(2x−3)=14 → x+4x−6=14 → 5x=20 → x=4; y=2(4)−3=5.'),
('math', 'A father is 3 times as old as his son. In 12 years, he will be twice as old. How old is the son now?', NULL, '["10", "11", "12", "14"]'::jsonb, 2, 3, 'f=3s; f+12=2(s+12) → 3s+12=2s+24 → s=12.'),
('math', 'A right triangle has legs 7 and 24. What is the hypotenuse?', NULL, '["23", "25", "26", "31"]'::jsonb, 1, 3, 'c² = 49 + 576 = 625 → c = 25.'),
('math', 'A circle is inscribed in a square with side 10. What is the area of the circle? (Use π ≈ 3.14)', NULL, '["62.8", "78.5", "100", "314"]'::jsonb, 1, 3, 'Radius = 5; Area = 3.14 × 25 = 78.5.'),
('math', 'A rectangular prism has volume 360 cm³. Its length is 10 and width is 6. What is its height?', NULL, '["4", "5", "6", "8"]'::jsonb, 2, 3, 'V = l×w×h → 360 = 10×6×h → 360 = 60h → h = 6.'),
('math', 'What is the area of a triangle with vertices at (0,0), (6,0), and (0,8)?', NULL, '["20", "24", "28", "48"]'::jsonb, 1, 3, 'Base = 6, height = 8; Area = (1/2)×6×8 = 24.'),
('math', 'Two angles of a triangle are 48° and 67°. What is the exterior angle at the third vertex?', NULL, '["65\u00b0", "90\u00b0", "115\u00b0", "180\u00b0"]'::jsonb, 2, 3, 'Third interior angle = 180−48−67 = 65°; exterior angle = 180−65 = 115°.'),
('math', 'A right triangle has hypotenuse 26 and one leg 10. What is the other leg?', NULL, '["16", "20", "24", "28"]'::jsonb, 2, 3, 'leg² = 26²−10² = 676−100 = 576 → leg = 24.'),
('math', 'A circle has area 200.96 square cm. What is its radius? (Use π ≈ 3.14)', NULL, '["4", "6", "7", "8"]'::jsonb, 3, 3, '200.96 = 3.14 × r² → r² = 64 → r = 8.'),
('math', 'A cylinder has radius 3 and height 10. What is its volume? (Use π ≈ 3.14)', NULL, '["94.2", "188.4", "282.6", "565.2"]'::jsonb, 2, 3, 'V = π × r² × h = 3.14 × 9 × 10 = 282.6.'),
('math', 'A square is inscribed in a circle with radius 5. What is the area of the square?', NULL, '["25", "50", "78.5", "100"]'::jsonb, 1, 3, 'Diagonal of the square = 2r = 10. Side = 10/√2 = 5√2. Area = (5√2)² = 50.'),
('math', 'Two parallel lines are cut by a transversal. One co-interior angle is 65°. What is the other co-interior angle?', NULL, '["65\u00b0", "90\u00b0", "115\u00b0", "180\u00b0"]'::jsonb, 2, 3, 'Co-interior (same-side interior) angles are supplementary: 180−65 = 115°.'),
('math', 'A right triangle with legs 9 and 40 has what hypotenuse?', NULL, '["41", "42", "43", "49"]'::jsonb, 0, 3, 'c² = 81 + 1600 = 1681 → c = 41.'),
('math', 'Pipe X fills a tank in 8 hours; Pipe Y drains it in 12 hours. Both open together — how long to fill the tank?', NULL, '["16 hours", "20 hours", "24 hours", "32 hours"]'::jsonb, 2, 3, 'Net rate = 1/8 − 1/12 = 3/24 − 2/24 = 1/24 per hour. Time = 24 hours.'),
('math', 'A jar has red and blue marbles in ratio 3:5. If there are 40 marbles total, how many are red?', NULL, '["12", "15", "16", "24"]'::jsonb, 1, 3, '3/8 × 40 = 15 red marbles.'),
('math', 'Two workers together finish a job in 6 hours. One alone takes 10 hours. How long does the other take alone?', NULL, '["12 hours", "15 hours", "18 hours", "20 hours"]'::jsonb, 1, 3, '1/6 − 1/10 = 5/30 − 3/30 = 2/30 = 1/15. Other takes 15 hours.'),
('math', 'A 30-liter solution is 40% acid. How many liters of pure acid must be added to make it 50% acid?', NULL, '["4", "6", "8", "10"]'::jsonb, 1, 3, 'Acid present: 0.40×30=12 L. After adding x L: (12+x)/(30+x)=0.50 → 12+x=15+0.5x → 0.5x=3 → x=6.'),
('math', 'A boat travels 24 miles upstream in 3 hours and the same distance downstream in 2 hours. What is the speed of the current?', NULL, '["1 mph", "2 mph", "3 mph", "4 mph"]'::jsonb, 1, 3, 'Upstream speed=8 mph; downstream speed=12 mph. Current=(12−8)/2=2 mph.'),
('math', 'Person A can paint a fence in 5 hours. Person B takes 7 hours. Working together, how long? (Round to nearest tenth)', NULL, '["2.5 hours", "2.9 hours", "3.1 hours", "3.5 hours"]'::jsonb, 1, 3, 'Rate = 1/5 + 1/7 = 12/35. Time = 35/12 ≈ 2.9 hours.'),
('math', 'A mixture of nuts costs $6/lb. Cashews cost $8/lb and peanuts cost $4/lb. What fraction of the mix is cashews?', NULL, '["1/4", "1/3", "1/2", "2/3"]'::jsonb, 2, 3, 'Let c = fraction cashews; 8c + 4(1−c) = 6 → 4c = 2 → c = 1/2.'),
('math', 'A price dropped from $250 to $200. What is the percent decrease?', NULL, '["15%", "20%", "25%", "30%"]'::jsonb, 1, 2, 'Decrease = 50; percent = 50/250 × 100 = 20%.'),
('math', 'After a 20% increase, a price is $156. What was the original price?', NULL, '["$120", "$125", "$130", "$140"]'::jsonb, 2, 2, '1.20 × p = 156 → p = 156 ÷ 1.20 = 130.'),
('math', 'What is 2/7 ÷ 4/21?', NULL, '["3/2", "3", "8/147", "7/6"]'::jsonb, 1, 3, '2/7 ÷ 4/21 = 2/7 × 21/4 = 42/28 = 3.'),
('math', 'A store offers successive discounts of 20% and 10%. What is the effective percent discount on the original price?', NULL, '["25%", "28%", "30%", "32%"]'::jsonb, 1, 3, '0.80 × 0.90 = 0.72; total discount = 28%.'),
('math', 'What is 5/6 × 3/4 ÷ 5/8?', NULL, '["1/2", "1", "5/4", "3/2"]'::jsonb, 1, 3, '5/6 × 3/4 = 15/24 = 5/8; then 5/8 ÷ 5/8 = 1.'),
('math', 'After two successive 10% increases, what is the overall percent increase?', NULL, '["20%", "21%", "22%", "25%"]'::jsonb, 1, 3, '1.10 × 1.10 = 1.21; overall increase = 21%.'),
('math', 'Six test scores are 70, 75, 80, 85, 90, and x. The mean is 82. What is x?', NULL, '["92", "94", "96", "98"]'::jsonb, 0, 3, 'Sum needed = 82 × 6 = 492; 70+75+80+85+90 = 400; x = 492 − 400 = 92.'),
('language', 'Which sentence uses punctuation correctly?', NULL, '["She went to the store, and bought milk.", "She went to the store and bought milk.", "She went to the store and, bought milk.", "She went, to the store and bought milk."]'::jsonb, 1, 1, 'No comma before ''and'' when joining two verbs with the same subject.'),
('language', 'Which sentence is correctly capitalized?', NULL, '["We visited the grand canyon last Summer.", "we visited the Grand Canyon last summer.", "We visited the Grand Canyon last summer.", "We visited The Grand Canyon last summer."]'::jsonb, 2, 1, 'Grand Canyon is a proper noun; ''summer'' is not.'),
('language', 'Which word is spelled correctly?', NULL, '["Recieve", "Recive", "Receive", "Receeve"]'::jsonb, 2, 1, 'R-E-C-E-I-V-E — ''i before e except after c.'''),
('language', 'Choose the grammatically correct sentence.', NULL, '["Each of the students have completed their project.", "Each of the students has completed their project.", "Each of the students have completed his project.", "Each of the students has completed their projects."]'::jsonb, 1, 2, '''Each'' is singular -> ''has.'''),
('language', 'Which sentence uses the apostrophe correctly?', NULL, '["The dog''s bone is buried in the yard''s.", "The dogs bone is buried in the yard.", "The dog''s bone is buried in the yard.", "The dogs'' bone is buried in the yard."]'::jsonb, 2, 2, 'Dog''s (singular possessive) is correct.'),
('language', 'Which sentence best fits as a topic sentence about exercise benefits?', NULL, '["Many people find exercise boring.", "Running shoes come in many styles.", "Regular exercise offers numerous physical and mental health benefits.", "Some athletes train many hours per day."]'::jsonb, 2, 2, 'A topic sentence states the paragraph''s main idea.'),
('language', 'Choose the correctly written sentence.', NULL, '["Between you and I, this is a great idea.", "Between you and me, this is a great idea.", "Between you and myself, this is a great idea.", "Between I and you, this is a great idea."]'::jsonb, 1, 2, '''Between'' is a preposition requiring object pronouns. ''Me'' is correct.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["Neither the coach nor the players was ready.", "Neither the coach nor the players were ready.", "Neither the coach nor the players is ready.", "Neither the coach nor the players are ready."]'::jsonb, 1, 3, 'With ''neither...nor,'' verb agrees with closer subject — ''players'' (plural) -> ''were.'''),
('language', 'Which sentence uses the semicolon correctly?', NULL, '["She studied hard; but she failed.", "She studied hard; she passed with high marks.", "She studied; hard and passed.", "She; studied hard and passed."]'::jsonb, 1, 3, 'Semicolons join two independent clauses without a conjunction.'),
('language', 'Which sentence contains a dangling modifier?', NULL, '["Running through the park, the dog chased the squirrel.", "Running through the park, the squirrel was chased by Sarah.", "Sarah chased the squirrel through the park.", "The squirrel ran as Sarah chased it."]'::jsonb, 1, 3, 'In B, ''Running through the park'' modifies ''squirrel'' — but Sarah was running.'),
('language', 'Which word is spelled correctly?', NULL, '["Accomodate", "Acommodate", "Accommodate", "Acomodate"]'::jsonb, 2, 1, 'Accommodate has two c''s and two m''s.'),
('language', 'Which word is spelled correctly?', NULL, '["Embarass", "Embarrass", "Embarras", "Embaras"]'::jsonb, 1, 1, 'Embarrass has two r''s and two s''s.'),
('language', 'Which word is spelled correctly?', NULL, '["Necesary", "Neccesary", "Neccessary", "Necessary"]'::jsonb, 3, 1, 'Necessary: one c, two s''s — ''one collar, two socks.'''),
('language', 'Which word is spelled correctly?', NULL, '["Seperate", "Seprate", "Separate", "Separrate"]'::jsonb, 2, 1, 'Separate: there is ''a rat'' in sepa-rat-e.'),
('language', 'Which word is spelled correctly?', NULL, '["Occurance", "Occurence", "Occurrance", "Occurrence"]'::jsonb, 3, 1, 'Occurrence: double c, double r, -ence ending.'),
('language', 'Which word is spelled correctly?', NULL, '["Exagerate", "Exaggerate", "Exaggarate", "Exaggerrate"]'::jsonb, 1, 1, 'Exaggerate has double g.'),
('language', 'Which word is spelled correctly?', NULL, '["Privelege", "Priviledge", "Privilege", "Privilige"]'::jsonb, 2, 1, 'Privilege: no ''d,'' ends in -lege.'),
('language', 'Which word is spelled correctly?', NULL, '["Aquaint", "Acquaint", "Acqaint", "Acquiant"]'::jsonb, 1, 1, 'Acquaint: a-c-q-u-a-i-n-t.'),
('language', 'Which word is spelled correctly?', NULL, '["Conscientous", "Consciencious", "Conscientious", "Consientious"]'::jsonb, 2, 1, 'Conscientious: c-o-n-s-c-i-e-n-t-i-o-u-s.'),
('language', 'Which word is spelled correctly?', NULL, '["Liason", "Liaison", "Liasson", "Liasion"]'::jsonb, 1, 1, 'Liaison: l-i-a-i-s-o-n — two i''s.'),
('language', 'Which word is spelled correctly?', NULL, '["Definately", "Definitly", "Definiteley", "Definitely"]'::jsonb, 3, 1, 'Definitely comes from ''definite'' + -ly.'),
('language', 'Which word is spelled correctly?', NULL, '["Calender", "Calandar", "Calandr", "Calendar"]'::jsonb, 3, 1, 'Calendar: c-a-l-e-n-d-a-r.'),
('language', 'Which word is spelled correctly?', NULL, '["Grammer", "Gramer", "Grammir", "Grammar"]'::jsonb, 3, 1, 'Grammar ends in -ar, not -er.'),
('language', 'Which word is spelled correctly?', NULL, '["Restarant", "Restuarant", "Restaurant", "Restorant"]'::jsonb, 2, 1, 'Restaurant: r-e-s-t-a-u-r-a-n-t.'),
('language', 'Which word is spelled correctly?', NULL, '["Beleive", "Beleve", "Believe", "Belive"]'::jsonb, 2, 1, 'Believe: b-e-l-i-e-v-e — ''i before e except after c.'''),
('language', 'Which word is spelled correctly?', NULL, '["Wierd", "Wired", "Weird", "Weerd"]'::jsonb, 2, 1, 'Weird is an exception: ''e before i'' — w-e-i-r-d.'),
('language', 'Which word is spelled correctly?', NULL, '["Arguement", "Arugment", "Arguemnt", "Argument"]'::jsonb, 3, 1, 'Argument drops the ''e'' from argue before adding -ment.'),
('language', 'Which word is spelled correctly?', NULL, '["Noticable", "Noticeable", "Notiseable", "Noticeble"]'::jsonb, 1, 1, 'Noticeable keeps the ''e'' from notice before -able to preserve the soft ''c.'''),
('language', 'Which word is spelled correctly?', NULL, '["Writting", "Writing", "Writeing", "Writen"]'::jsonb, 1, 1, 'Writing: drop the silent ''e'' from write before adding -ing.'),
('language', 'Which word is spelled correctly?', NULL, '["Begining", "Begginning", "Beggining", "Beginning"]'::jsonb, 3, 1, 'Beginning: double the ''n'' — b-e-g-i-n-n-i-n-g.'),
('language', 'Which word is spelled correctly?', NULL, '["Febuary", "Feburary", "February", "Febrary"]'::jsonb, 2, 1, 'February: F-e-b-r-u-a-r-y — don''t drop the first ''r.'''),
('language', 'Which word is spelled correctly?', NULL, '["Suprise", "Surprize", "Surprisse", "Surprise"]'::jsonb, 3, 1, 'Surprise: s-u-r-p-r-i-s-e — two r''s, one s.'),
('language', 'Which word is spelled correctly?', NULL, '["Nieghbor", "Neighbor", "Naighbor", "Nieghbour"]'::jsonb, 1, 1, 'Neighbor: n-e-i-g-h-b-o-r — ''e before i'' after ''n.'''),
('language', 'Which word is spelled correctly?', NULL, '["Knowlege", "Knowlegde", "Knowledg", "Knowledge"]'::jsonb, 3, 1, 'Knowledge: k-n-o-w-l-e-d-g-e.'),
('language', 'Which word is spelled correctly?', NULL, '["Succedd", "Sucseed", "Succeed", "Suceed"]'::jsonb, 2, 1, 'Succeed: s-u-c-c-e-e-d — double c, double e.'),
('language', 'Which word is spelled correctly?', NULL, '["Mispell", "Misspell", "Misspel", "Missppell"]'::jsonb, 1, 1, 'Misspell: mis- + spell — two s''s.'),
('language', 'Which word is spelled correctly?', NULL, '["Untill", "Unttil", "Untl", "Until"]'::jsonb, 3, 1, 'Until: u-n-t-i-l — one ''l'' at the end.'),
('language', 'Which word is spelled correctly?', NULL, '["Enviroment", "Enviornment", "Environement", "Environment"]'::jsonb, 3, 1, 'Environment: e-n-v-i-r-o-n-m-e-n-t.'),
('language', 'Which word is spelled correctly?', NULL, '["Minature", "Miniature", "Minuature", "Miniuture"]'::jsonb, 1, 1, 'Miniature: m-i-n-i-a-t-u-r-e — keep both i''s.'),
('language', 'Which word is spelled correctly?', NULL, '["Millenium", "Milennium", "Millennium", "Milenneum"]'::jsonb, 2, 1, 'Millennium: double l, double n — m-i-l-l-e-n-n-i-u-m.'),
('language', 'Which sentence is correctly capitalized?', NULL, '["My favorite subject is Math.", "My favorite subject is math.", "my favorite subject is Math.", "My Favorite Subject is math."]'::jsonb, 1, 1, 'School subjects are not proper nouns and are not capitalized.'),
('language', 'Which sentence is correctly capitalized?', NULL, '["We drove across the mississippi river.", "We drove across the Mississippi River.", "We drove across the Mississippi river.", "We Drove Across The Mississippi River."]'::jsonb, 1, 1, 'Mississippi River is a proper noun — both words are capitalized.'),
('language', 'Which sentence is correctly capitalized?', NULL, '["She loves spring and Summer.", "She loves Spring and summer.", "She loves spring and summer.", "She Loves Spring And Summer."]'::jsonb, 2, 1, 'Seasons (spring, summer, fall, winter) are not capitalized.'),
('language', 'Which sentence is correctly capitalized?', NULL, '["I read a book by dr. seuss.", "I read a book by Dr. Seuss.", "I read a book by dr. Seuss.", "I read a book by Dr. seuss."]'::jsonb, 1, 1, '''Dr.'' is a title before a name and is capitalized; ''Seuss'' is a proper noun.'),
('language', 'Which sentence is correctly capitalized?', NULL, '["The capital of France is paris.", "The capital of france is Paris.", "The Capital of France is Paris.", "The capital of France is Paris."]'::jsonb, 3, 1, 'France and Paris are proper nouns; ''capital'' is a common noun.'),
('language', 'Which sentence is correctly capitalized?', NULL, '["She shops at walmart every friday.", "She shops at Walmart every Friday.", "She shops at Walmart every friday.", "She shops at walmart every Friday."]'::jsonb, 1, 1, 'Walmart is a brand name (proper noun); Friday is a day of the week — both capitalized.'),
('language', 'Which sentence is correctly capitalized?', NULL, '["I visited aunt Maria last tuesday.", "I visited Aunt Maria last Tuesday.", "I visited aunt Maria last Tuesday.", "I visited Aunt maria last Tuesday."]'::jsonb, 1, 1, '''Aunt'' used directly before a name acts as a title and is capitalized; Tuesday is a day of the week.'),
('language', 'Which sentence is correctly capitalized?', NULL, '["He moved to the west to find work.", "He moved to the West to find work.", "He Moved To The West To Find Work.", "He moved to the west To find work."]'::jsonb, 1, 1, 'When ''West'' refers to a specific region (not a direction), it is capitalized.'),
('language', 'Which sentence is correctly capitalized?', NULL, '["The book is called the call of the wild.", "The book is called The Call of the Wild.", "The book is called The Call Of The Wild.", "The book is called the Call of the Wild."]'::jsonb, 1, 1, 'In titles, capitalize the first word, last word, and all major words; ''of'' and ''the'' (not first) are lowercase.'),
('language', 'Which sentence is correctly capitalized?', NULL, '["My teacher is named mr. johnson.", "My teacher is named mr. Johnson.", "My teacher is named Mr. Johnson.", "My teacher is named Mr. johnson."]'::jsonb, 2, 1, '''Mr.'' is a title before a name; both ''Mr.'' and ''Johnson'' are capitalized.'),
('language', 'Which sentence uses commas correctly?', NULL, '["I need eggs milk, and butter.", "I need eggs, milk and butter.", "I need eggs, milk, and butter.", "I need, eggs, milk, and butter."]'::jsonb, 2, 2, 'Serial comma rule: use commas between all items in a series, including before ''and.'''),
('language', 'Which sentence uses the comma correctly?', NULL, '["After the game we went home.", "After the game, we went home.", "After, the game we went home.", "After the game we, went home."]'::jsonb, 1, 2, 'Use a comma after an introductory prepositional phrase.'),
('language', 'Which sentence uses commas correctly?', NULL, '["My brother, who lives in Denver loves skiing.", "My brother who lives in Denver, loves skiing.", "My brother, who lives in Denver, loves skiing.", "My brother who lives, in Denver loves skiing."]'::jsonb, 2, 2, 'Nonrestrictive (non-essential) clauses are set off by commas on both sides.'),
('language', 'Which sentence uses the comma correctly?', NULL, '["We can leave early, or stay for the whole show.", "We can leave early or, stay for the whole show.", "We can leave, early or stay for the whole show.", "We can leave early or stay for the whole show."]'::jsonb, 3, 2, 'No comma before ''or'' when it joins two verbs (not two independent clauses) with the same subject.'),
('language', 'Which sentence uses commas correctly?', NULL, '["Yes I agree with your decision.", "Yes, I agree with your decision.", "Yes I agree, with your decision.", "Yes, I agree, with your decision."]'::jsonb, 1, 2, 'Introductory words and interjections like ''Yes'' and ''No'' are followed by a comma.'),
('language', 'Which sentence uses the comma correctly?', NULL, '["Maria my best friend moved away last year.", "Maria, my best friend, moved away last year.", "Maria, my best friend moved away last year.", "Maria my best, friend moved away last year."]'::jsonb, 1, 2, 'Appositives — phrases that rename a noun — are set off with commas.'),
('language', 'Which sentence uses commas correctly?', NULL, '["The tall, dark, mysterious stranger walked in.", "The tall dark mysterious stranger walked in.", "The, tall dark mysterious stranger walked in.", "The tall, dark mysterious stranger walked in."]'::jsonb, 0, 2, 'Use commas to separate coordinate adjectives — adjectives that equally modify the same noun.'),
('language', 'Which sentence uses the comma correctly?', NULL, '["He was born on March, 15 2010.", "He was born on March 15, 2010.", "He was born on March 15 2010.", "He was born, on March 15, 2010."]'::jsonb, 1, 2, 'In a date, use a comma between the day and the year: March 15, 2010.'),
('language', 'Which sentence uses commas correctly?', NULL, '["We visited Paris France on our trip.", "We visited Paris, France, on our trip.", "We visited Paris France, on our trip.", "We visited, Paris France on our trip."]'::jsonb, 1, 2, 'When a city and country (or state) appear together, commas follow the city and the country/state.'),
('language', 'Which sentence uses the comma correctly?', NULL, '["Although she was tired she kept studying.", "Although she was tired, she kept studying.", "Although, she was tired she kept studying.", "Although she was tired she kept, studying."]'::jsonb, 1, 2, 'Use a comma after an introductory subordinate clause.'),
('language', 'Which sentence uses commas correctly?', NULL, '["I bought apples oranges and grapes at the market.", "I bought apples, oranges, and grapes at the market.", "I bought apples, oranges and, grapes at the market.", "I bought, apples, oranges, and grapes at the market."]'::jsonb, 1, 2, 'Serial comma rule: separate all items in a list, including with a comma before the final ''and.'''),
('language', 'Which sentence uses the comma correctly?', NULL, '["James please close the door.", "James please, close the door.", "James, please close the door.", "James please close, the door."]'::jsonb, 2, 2, 'Use a comma to set off a direct address (vocative) from the rest of the sentence.'),
('language', 'Which sentence uses commas correctly with a compound sentence?', NULL, '["She finished her homework and then she watched TV.", "She finished her homework, and then she watched TV.", "She finished her homework and, then she watched TV.", "She finished her homework, and, then she watched TV."]'::jsonb, 1, 2, 'Use a comma before a coordinating conjunction joining two independent clauses.'),
('language', 'Which sentence uses the comma correctly?', NULL, '["Running down the hall, the bell rang loudly.", "Running down the hall the student heard the bell.", "Running down the hall, the student heard the bell.", "Running down the hall the, student heard the bell."]'::jsonb, 2, 2, 'Use a comma after a participial phrase that begins a sentence.'),
('language', 'Which sentence uses commas correctly?', NULL, '["The results were however not what we expected.", "The results were, however not what we expected.", "The results were, however, not what we expected.", "The results were however, not what we expected."]'::jsonb, 2, 2, 'Conjunctive adverbs like ''however'' used mid-sentence are set off by commas on both sides.'),
('language', 'Which sentence uses the comma correctly?', NULL, '["She has three dogs a golden retriever a poodle and a beagle.", "She has three dogs, a golden retriever, a poodle, and a beagle.", "She has three dogs a golden retriever, a poodle, and a beagle.", "She has, three dogs a golden retriever a poodle and a beagle."]'::jsonb, 1, 2, 'Serial commas separate all items in a list; the appositive list following ''three dogs'' needs commas between each item.'),
('language', 'Which sentence uses the comma correctly?', NULL, '["The small, red car was parked outside.", "The small red, car was parked outside.", "The, small red car was parked outside.", "The small red car, was parked outside."]'::jsonb, 0, 2, '''Small'' and ''red'' are coordinate adjectives equally modifying ''car'' — separate with a comma.'),
('language', 'Which sentence uses the comma correctly?', NULL, '["When it rains, I like to read indoors.", "When it rains I like to read, indoors.", "When, it rains I like to read indoors.", "When it rains I like, to read indoors."]'::jsonb, 0, 2, 'Use a comma after an introductory dependent clause.'),
('language', 'Which sentence uses the comma correctly?', NULL, '["He is, I believe a talented musician.", "He is I believe, a talented musician.", "He is, I believe, a talented musician.", "He is I believe a talented musician."]'::jsonb, 2, 2, 'Parenthetical expressions (''I believe'') are set off from the rest of the sentence by commas.'),
('language', 'Which sentence uses the comma correctly?', NULL, '["That is my dog Buddy the golden retriever.", "That is my dog, Buddy, the golden retriever.", "That is my dog Buddy, the golden retriever.", "That is my dog, Buddy the golden retriever."]'::jsonb, 1, 2, 'Two consecutive appositives (''Buddy'' and ''the golden retriever'') are each set off by commas.'),
('language', 'Which sentence uses the comma correctly?', NULL, '["The teacher said that we should study every night.", "The teacher said, that we should study every night.", "The teacher, said that we should study every night.", "The teacher said that we should, study every night."]'::jsonb, 0, 2, 'Do not use a comma before an indirect quotation introduced by ''that.'''),
('language', 'Which sentence uses the comma correctly?', NULL, '["Students who study regularly tend to earn better grades.", "Students, who study regularly, tend to earn better grades.", "Students who, study regularly tend to earn better grades.", "Students who study, regularly tend to earn better grades."]'::jsonb, 0, 2, 'Restrictive clauses (that define which students) are not set off by commas.'),
('language', 'Which sentence uses commas correctly in a series of actions?', NULL, '["She walked into the room sat down and opened her book.", "She walked into the room, sat down, and opened her book.", "She walked, into the room, sat down and opened her book.", "She walked into the room sat, down, and opened her book."]'::jsonb, 1, 2, 'Use serial commas to separate three or more items (including actions) in a series.'),
('language', 'Which sentence uses the comma correctly?', NULL, '["No I do not think that is a good idea.", "No, I do not think that is a good idea.", "No I, do not think that is a good idea.", "No I do not think, that is a good idea."]'::jsonb, 1, 2, 'Introductory words ''Yes,'' ''No,'' and ''Well'' are followed by a comma.'),
('language', 'Which sentence uses the comma correctly?', NULL, '["We drove through Dallas Texas and then headed north.", "We drove through Dallas, Texas, and then headed north.", "We drove through Dallas Texas, and then headed north.", "We drove through Dallas, Texas and then headed north."]'::jsonb, 1, 2, 'When a state follows a city, a comma comes after both the city and the state.'),
('language', 'Which sentence uses the apostrophe correctly?', NULL, '["Its time to leave for school.", "It''s time to leave for school.", "Its'' time to leave for school.", "It''ss time to leave for school."]'::jsonb, 1, 2, '''It''s'' is the contraction of ''it is.'' ''Its'' (no apostrophe) is the possessive pronoun.'),
('language', 'Which sentence uses the apostrophe correctly?', NULL, '["The two boy''s bikes were stolen.", "The two boys bike''s were stolen.", "The two boys'' bikes were stolen.", "The two boys bikes'' were stolen."]'::jsonb, 2, 2, 'Plural possessive: boys'' (apostrophe after the ''s'' of the plural noun).'),
('language', 'Which sentence uses the colon correctly?', NULL, '["She needed: eggs, milk, and flour.", "She needed eggs, milk: and flour.", "She needed eggs: milk and flour.", "She needed three things: eggs, milk, and flour."]'::jsonb, 3, 2, 'Use a colon after a complete sentence to introduce a list.'),
('language', 'Which sentence uses the apostrophe correctly?', NULL, '["The childrens'' playground was closed.", "The children''s playground was closed.", "The childrens playground was closed.", "The childrens''s playground was closed."]'::jsonb, 1, 2, 'Children is already plural (irregular); add ''s to form the possessive: children''s.'),
('language', 'Which sentence uses the semicolon correctly?', NULL, '["I enjoy hiking; but not in the rain.", "I enjoy hiking; however, I avoid muddy trails.", "I enjoy; hiking in the mountains.", "I enjoy hiking, however; I avoid muddy trails."]'::jsonb, 1, 2, 'A semicolon correctly precedes a conjunctive adverb like ''however'' that joins two independent clauses.'),
('language', 'Which sentence uses the colon correctly?', NULL, '["My three favorite sports are: soccer, basketball, and tennis.", "My three favorite sports: are soccer, basketball, and tennis.", "My three favorite sports are soccer, basketball: and tennis.", "My three favorite sports are soccer: basketball, and tennis."]'::jsonb, 0, 2, 'A colon after ''are'' introducing a list is standard; all other options place the colon in mid-predicate or mid-list positions.'),
('language', 'Which sentence uses the apostrophe correctly?', NULL, '["That car is her''s.", "That car is hers''.", "That car is hers.", "That car is her''s''."]'::jsonb, 2, 2, 'Possessive pronouns (hers, his, its, ours, theirs, yours) never use apostrophes.'),
('language', 'Which sentence uses the semicolon correctly?', NULL, '["Marcus loves to cook; and he often bakes bread.", "Marcus loves to cook; in fact, he bakes his own bread.", "Marcus loves; to cook and bake bread.", "Marcus loves to; cook and bake bread."]'::jsonb, 1, 2, 'Semicolons correctly precede conjunctive adverbs (''in fact'') joining two independent clauses.'),
('language', 'Which sentence uses the apostrophe correctly?', NULL, '["Can''t you see I''m busy?", "Cant you see Im busy?", "Can''t you see Im busy?", "Cant you see I''m busy?"]'::jsonb, 0, 2, 'Both ''can''t'' (cannot) and ''I''m'' (I am) require apostrophes to mark omitted letters.'),
('language', 'Which sentence uses the colon correctly?', NULL, '["The coach gave one piece of advice: practice daily.", "The coach gave: one piece of advice practice daily.", "The coach gave one piece of advice practice: daily.", "The coach: gave one piece of advice practice daily."]'::jsonb, 0, 2, 'A colon after a complete independent clause introduces a summary or direct explanation.'),
('language', 'Which sentence uses the apostrophe correctly?', NULL, '["We''re going to the movies tonight.", "Were going to the movies tonight.", "We''r going to the movies tonight.", "We''re'' going to the movies tonight."]'::jsonb, 0, 2, '''We''re'' is the contraction of ''we are'' — the apostrophe replaces the ''a.'''),
('language', 'Which sentence uses the apostrophe correctly?', NULL, '["The boss''s office is on the third floor.", "The boss'' office is on the third floor.", "The bosses office is on the third floor.", "The bosses'' office is on the third floor."]'::jsonb, 0, 2, 'For singular nouns ending in ''s,'' add ''s to form the possessive: boss''s.'),
('language', 'Which sentence uses the semicolon correctly?', NULL, '["The storm hit last night; causing widespread damage.", "The storm hit last night; the damage was widespread.", "The storm; hit last night causing widespread damage.", "The storm hit; last night causing widespread damage."]'::jsonb, 1, 2, 'A semicolon joins two complete, related independent clauses. ''Causing widespread damage'' is not an independent clause.'),
('language', 'Which sentence uses the colon correctly?', NULL, '["The reason is clear: she forgot to study.", "The reason: is clear she forgot to study.", "The reason is: clear she forgot to study.", "The reason is clear she: forgot to study."]'::jsonb, 0, 2, 'A colon after a complete independent clause introduces an explanation or clarification.'),
('language', 'Which sentence uses the apostrophe correctly?', NULL, '["You''re shoes are untied.", "Your shoes are untied.", "Youre shoes are untied.", "Your'' shoes are untied."]'::jsonb, 1, 2, '''Your'' is the possessive pronoun; ''you''re'' = you are. No apostrophe needed here.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["The team are playing their best game.", "The team is playing its best game.", "The team is playing their best game.", "The team are playing its best game."]'::jsonb, 1, 2, '''Team'' is a collective noun treated as singular in American English: ''is'' and ''its.'''),
('language', 'Choose the grammatically correct sentence.', NULL, '["He don''t know the answer.", "He doesn''t knows the answer.", "He doesn''t know the answer.", "He do not knows the answer."]'::jsonb, 2, 2, 'Third-person singular present requires ''doesn''t'' (does not) + base verb.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["She runs more faster than her brother.", "She runs fastest than her brother.", "She runs more fast than her brother.", "She runs faster than her brother."]'::jsonb, 3, 2, 'Comparative form of ''fast'' is ''faster,'' not ''more faster'' (double comparative).'),
('language', 'Choose the grammatically correct sentence.', NULL, '["I can''t hardly wait for the concert.", "I can''t wait hardly for the concert.", "I can hardly wait for the concert.", "I can''t hardly wait hardly for the concert."]'::jsonb, 2, 2, 'Double negative rule: ''can''t hardly'' creates a double negative. Use ''can hardly'' instead.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["The data shows that the experiment failed.", "The data show that the experiment failed.", "The data is showing that the experiment failed.", "The data were showing that the experiment failed."]'::jsonb, 1, 2, '''Data'' is the plural of ''datum'' — use the plural verb ''show.'''),
('language', 'Choose the correctly written sentence.', NULL, '["Lay down and rest for a while.", "Lie down and rest for a while.", "Lay yourself down and rest for a while.", "Lays down and rest for a while."]'::jsonb, 1, 2, '''Lie'' means to recline (intransitive). ''Lay'' requires a direct object.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["Everyone have submitted their forms.", "Everyone has submitted their forms.", "Everyone have submitted his form.", "Everyone has submitted his or her forms."]'::jsonb, 1, 2, '''Everyone'' is singular -> ''has.'' Using ''their'' as a singular neutral pronoun is widely accepted.'),
('language', 'Choose the correctly written sentence.', NULL, '["I feel badly about missing the party.", "I feel bad about missing the party.", "I feel more bad about missing the party.", "I feel badder about missing the party."]'::jsonb, 1, 2, '''Feel'' is a linking verb — use the adjective ''bad,'' not the adverb ''badly.'''),
('language', 'Choose the grammatically correct sentence.', NULL, '["Him and his friend went to the mall.", "He and his friend went to the mall.", "Him and his friend goed to the mall.", "He and his friend go to the mall yesterday."]'::jsonb, 1, 2, 'Pronoun case: ''He'' (subject pronoun) is required as the subject of the sentence.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["The number of students are increasing.", "A number of students is signing up.", "The number of students is increasing.", "A number of students are is signing up."]'::jsonb, 2, 2, '''The number'' takes a singular verb; ''a number of'' takes a plural verb.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["She is more smarter than anyone in class.", "She is smarter than anyone else in class.", "She is the more smart than anyone in class.", "She is the most smartest in class."]'::jsonb, 1, 2, 'Avoid double superlatives; ''else'' is needed to exclude the subject from the group being compared.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["Please give the package to whoever answers the door.", "Please give the package to whomever answers the door.", "Please give the package to who answers the door.", "Please give the package to whom answers the door."]'::jsonb, 0, 2, '''Whoever'' is the subject of the embedded clause ''whoever answers the door.'''),
('language', 'Choose the grammatically correct sentence.', NULL, '["They played good in the finals.", "They played goodly in the finals.", "They played well in the finals.", "They played more good in the finals."]'::jsonb, 2, 2, '''Well'' is the adverb form and modifies the verb ''played.'' ''Good'' is an adjective.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["It was her who called last night.", "It was she who called last night.", "It was she whom called last night.", "It was her whom called last night."]'::jsonb, 1, 2, 'After a linking verb (''was''), use the subject pronoun ''she,'' not the object ''her.'''),
('language', 'Choose the grammatically correct sentence.', NULL, '["The committee have reached their decision.", "The committee has reached their decision.", "The committee has reached its decision.", "The committee have reached its decision."]'::jsonb, 2, 2, '''Committee'' is a collective noun (singular in American English) -> ''has'' and ''its.'''),
('language', 'Choose the grammatically correct sentence.', NULL, '["Neither of the answers are correct.", "Neither of the answers is correct.", "Neither answers are correct.", "Neither answers is correct."]'::jsonb, 1, 2, '''Neither'' as a subject pronoun takes a singular verb: ''is.'''),
('language', 'Choose the grammatically correct sentence.', NULL, '["I use to wake up early every morning.", "I used to wake up early every morning.", "I use to waked up early every morning.", "I used to waking up early every morning."]'::jsonb, 1, 2, '''Used to'' (past habit) is the correct form; ''use to'' is nonstandard.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["Less students attended today than yesterday.", "Fewer students attend today than yesterday.", "Fewer students attended today than yesterday.", "Less students attend today than yesterday."]'::jsonb, 2, 2, '''Fewer'' is used for countable nouns; ''less'' for uncountable quantities. Past tense ''attended'' is consistent.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["She is the tallest of the two sisters.", "She is the taller of the two sisters.", "She is more taller of the two sisters.", "She is tallest between the two sisters."]'::jsonb, 1, 2, 'When comparing exactly two things, use the comparative form (-er), not the superlative (-est).'),
('language', 'Choose the grammatically correct sentence.', NULL, '["The coach talked to Maria and I after practice.", "The coach talked to Maria and me after practice.", "The coach talked to Maria and myself after practice.", "The coach talked to I and Maria after practice."]'::jsonb, 1, 2, 'Object pronoun ''me'' is required after the preposition ''to.'' Remove ''Maria and'' to test: ''to me.'''),
('language', 'Choose the grammatically correct sentence.', NULL, '["She looked at the mirror and combed her hairs.", "She looked at the mirror and combed her hair.", "She looked to the mirror and combed her hair.", "She looked the mirror and combed her hair."]'::jsonb, 1, 2, '''Hair'' in reference to someone''s overall hair is an uncountable noun — no plural ''s.'''),
('language', 'Choose the grammatically correct sentence.', NULL, '["Can you borrow me your pencil?", "Can you lend me your pencil?", "Can I lend your pencil?", "Can you borrow your pencil to me?"]'::jsonb, 1, 2, '''Lend'' means to give temporarily; ''borrow'' means to take temporarily. You lend TO someone.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["I am taller then my father.", "I am more tall than my father.", "I am taller than my father.", "I am most taller than my father."]'::jsonb, 2, 2, '''Than'' is the correct conjunction for comparisons; ''then'' indicates time sequence.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["She don''t never miss practice.", "She doesn''t never miss practice.", "She never misses practice.", "She don''t miss never practice."]'::jsonb, 2, 2, 'Double negative rule: ''doesn''t never'' and ''don''t never'' are non-standard. Use a single negative.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["Its'' a beautiful morning outside.", "It''s a beautiful morning outside.", "It is'' a beautiful morning outside.", "Its a beautiful morning outside."]'::jsonb, 1, 2, '''It''s'' is the contraction of ''it is.'' Never add an apostrophe to ''its'' for possession.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["The principle of the school made an announcement.", "The principal of the school make an announcement.", "The principal of the school made an announcement.", "The principle of the school make an announcement."]'::jsonb, 2, 2, '''Principal'' (head of a school) vs. ''principle'' (a rule or belief). Past tense ''made'' is correct.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["She was laying on the couch all afternoon.", "She was lying on the couch all afternoon.", "She was lain on the couch all afternoon.", "She was lied on the couch all afternoon."]'::jsonb, 1, 2, '''Lying'' is the present participle of ''lie'' (to recline). ''Laying'' requires a direct object.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["The affect of the medicine was immediate.", "The effect of the medicine was immediate.", "The effect of the medicine were immediate.", "The affect of the medicine were immediate."]'::jsonb, 1, 2, '''Effect'' is the noun (result); ''affect'' is usually the verb (to influence).'),
('language', 'Choose the grammatically correct sentence.', NULL, '["He could of won if he had practiced.", "He could have won if he had practiced.", "He could of win if he had practiced.", "He could''ve of won if he had practiced."]'::jsonb, 1, 2, '''Could have'' (not ''could of'') is correct — ''of'' sounds like ''have'' in speech but is never correct in writing.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["She types more quicker than anyone on the team.", "She types quicklier than anyone on the team.", "She types more quickly than anyone on the team.", "She types more quick than anyone on the team."]'::jsonb, 2, 2, '''Quickly'' is an adverb; the comparative is ''more quickly'' (not ''quicker,'' which is an adjective comparative).'),
('language', 'Choose the grammatically correct sentence.', NULL, '["Between the three options, I like the first best.", "Among the three options, I like the first best.", "Among the three options, I like the first better.", "Between the three options, I like the first better."]'::jsonb, 1, 2, '''Among'' is used for three or more; ''between'' for exactly two. Superlative ''best'' compares three.'),
('language', 'Which sentence best serves as a concluding sentence for a paragraph about recycling?', NULL, '["Plastics are a major source of pollution.", "Clearly, recycling plays a vital role in protecting our planet for future generations.", "Many people do not recycle at their workplaces.", "Glass can be recycled many times without losing quality."]'::jsonb, 1, 2, 'A concluding sentence wraps up the paragraph''s main idea and signals closure.'),
('language', 'Which version best combines these two sentences: ''The movie was long. The movie was interesting.''?', NULL, '["The movie was long, interesting.", "Although the movie was long, it was interesting.", "The movie was long and interesting both.", "The movie was long it was interesting."]'::jsonb, 1, 2, 'Using ''Although'' creates a concise combined sentence and shows the contrast between ideas.'),
('language', 'Which sentence is a run-on?', NULL, '["The sun set; the stars appeared.", "The sun set, and the stars appeared.", "The sun set the stars appeared.", "After the sun set, the stars appeared."]'::jsonb, 2, 2, 'A run-on joins two independent clauses without a conjunction or punctuation.'),
('language', 'Which sentence is the most concise revision of ''Due to the fact that it was raining, we decided to postpone the game''?', NULL, '["Because it was raining we decided to postpone the game.", "Because it was raining, we postponed the game.", "It was raining, so we decided we would postpone the game at that time.", "We postponed the game, and the reason is that it was raining outside."]'::jsonb, 1, 2, 'Replacing ''due to the fact that'' with ''because'' and cutting ''decided to'' makes the sentence concise.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["She is one of the students who has excelled.", "She is one of the students who have excelled.", "She is one of the students whom has excelled.", "She is one of the students whom have excelled."]'::jsonb, 1, 3, 'The antecedent of ''who'' is the plural ''students,'' not ''one'' — so ''have'' is correct.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["Whomever arrives first should sign in.", "Whoever arrives first should sign in.", "Whomever arrives first should signs in.", "Who arrives first should sign in."]'::jsonb, 1, 3, '''Whoever'' is the subject of the embedded clause ''whoever arrives first.'' Subject = nominative case.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["The committee approved the proposal that it deemed most worthy.", "The committee approved the proposal what it deemed most worthy.", "The committee approved the proposal which they deemed most worthy.", "The committee approved the proposal whom it deemed most worthy."]'::jsonb, 0, 3, '''That'' introduces restrictive clauses for things; ''whom'' is for people; ''what'' is not a relative pronoun here.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["Having finished the exam, the questions seemed easy.", "Having finished the exam, the students thought the questions were easy.", "The questions, having finished the exam, seemed easy.", "Having finished the exam and the questions seemed easy."]'::jsonb, 1, 3, 'Dangling modifier rule: the participial phrase ''Having finished the exam'' must modify the subject ''students,'' not ''questions.'''),
('language', 'Choose the grammatically correct sentence.', NULL, '["Neither the teacher nor the students was prepared.", "Neither the students nor the teacher was prepared.", "Neither the students nor the teacher were prepared.", "Neither the teacher nor the students is prepared."]'::jsonb, 1, 3, 'With ''neither...nor,'' the verb agrees with the closer subject. ''Teacher'' (singular) is closer -> ''was.'''),
('language', 'Choose the grammatically correct sentence.', NULL, '["The man who I spoke to was very helpful.", "The man to whom I spoke was very helpful.", "The man whom I spoke was very helpful.", "The man which I spoke to was very helpful."]'::jsonb, 1, 3, '''Whom'' is the object of the preposition ''to''; moving the preposition in front makes the grammar explicit.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["Walking along the pier, the sunset was breathtaking.", "Walking along the pier, we found the sunset breathtaking.", "The sunset, walking along the pier, was breathtaking.", "We found the sunset breathtaking, walking along the pier."]'::jsonb, 1, 3, 'Dangling modifier rule: the participial phrase ''Walking along the pier'' must have the subject ''we'' immediately follow it.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["It is important that he attends the meeting.", "It is important that he attend the meeting.", "It is important that he attended the meeting.", "It is important that he attending the meeting."]'::jsonb, 1, 3, 'Subjunctive mood: after expressions of importance (''it is important that''), use the base verb: ''attend.'''),
('language', 'Choose the grammatically correct sentence.', NULL, '["If I was you, I would apologize immediately.", "If I were you, I would apologize immediately.", "If I am you, I would apologize immediately.", "If I be you, I would apologize immediately."]'::jsonb, 1, 3, 'Subjunctive mood for hypothetical or contrary-to-fact conditions: ''If I were you'' (not ''was'').'),
('language', 'Choose the grammatically correct sentence.', NULL, '["The reason she succeeded is because she practiced.", "The reason she succeeded is that she practiced.", "The reason she succeeded is due to she practiced.", "The reason she succeeded is for she practiced."]'::jsonb, 1, 3, '''The reason is that'' — not ''the reason is because.'' ''Because'' is redundant after ''reason.'''),
('language', 'Choose the grammatically correct sentence.', NULL, '["Scarcely had the game begun when it started to rain.", "Scarcely had the game begun than it started to rain.", "Scarcely had the game begun and it started to rain.", "Scarcely had the game began when it started to rain."]'::jsonb, 0, 3, '''Scarcely...when'' (not ''than'') is the correct idiomatic pair. ''Begun'' is the correct past participle of ''begin.'''),
('language', 'Choose the grammatically correct sentence.', NULL, '["The winners were him and her.", "The winners were he and she.", "The winners was him and her.", "The winners was he and she."]'::jsonb, 1, 3, 'After a linking verb (''were''), use subject (nominative) pronouns: ''he and she.'''),
('language', 'Choose the grammatically correct sentence.', NULL, '["She wants to quickly and accurately complete the form.", "She wants to complete the form quickly and accurately.", "She wants quickly and accurately to complete the form.", "Quickly and accurately, she wants to complete the form."]'::jsonb, 1, 3, 'Avoid split infinitives when a cleaner alternative exists; placing adverbs after the verb phrase is preferred.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["I wish I would have studied harder for the test.", "I wish I had studied harder for the test.", "I wish I studied harder for the test.", "I wish I was studied harder for the test."]'::jsonb, 1, 3, 'After ''wish'' for past regret, use the past perfect (''had studied''), not ''would have studied.'''),
('language', 'Choose the grammatically correct sentence.', NULL, '["She is taller than me by three inches.", "She is taller than I by three inches.", "She is taller than myself by three inches.", "She is taller than I am by three inches."]'::jsonb, 3, 3, 'In comparisons using ''than,'' stating the implied verb (''than I am'') is the clearest and most complete form.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["The news are disturbing.", "Mathematics are difficult.", "The news is disturbing.", "Physics are taught here."]'::jsonb, 2, 3, '''News,'' ''mathematics,'' ''physics,'' and similar -s words are singular nouns -> singular verb ''is.'''),
('language', 'Choose the grammatically correct sentence.', NULL, '["Hardly no one came to the event.", "Scarcely anyone came to the event.", "Barely nobody came to the event.", "Almost no one didn''t come to the event."]'::jsonb, 1, 3, '''Scarcely anyone'' is correct; ''hardly no one'' and ''barely nobody'' are double negatives.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["He is the kind of student who works hard and that gets results.", "He is the kind of student who works hard and who gets results.", "He is the kind of student which works hard and that gets results.", "He is the kind of student that works hard and which gets results."]'::jsonb, 1, 3, 'Parallel structure in relative clauses: ''who works hard and who gets results'' — keep the same relative pronoun.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["She not only cleaned her room but also organized her closet.", "She not only cleaned her room but organized also her closet.", "She not only cleaned her room, but also she organized her closet.", "Not only she cleaned her room but also organized her closet."]'::jsonb, 0, 3, 'Parallel structure with ''not only...but also'': both elements must have the same grammatical form (verb + object).'),
('language', 'Choose the grammatically correct sentence.', NULL, '["The professor, along with her students, are presenting today.", "The professor, along with her students, is presenting today.", "The professor along with her students is presenting today.", "The professor along with her students are presenting today."]'::jsonb, 1, 3, 'Phrases introduced by ''along with'' do not change the number of the subject. ''Professor'' (singular) -> ''is.'''),
('language', 'Choose the grammatically correct sentence.', NULL, '["I resent him leaving without saying goodbye.", "I resent him leave without saying goodbye.", "I resent his leaving without saying goodbye.", "I resent his leave without saying goodbye."]'::jsonb, 2, 3, 'A gerund (''leaving'') acts as a noun; the possessive pronoun (''his'') should modify it, not the object pronoun.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["Neither her talent nor her dedication have gone unnoticed.", "Neither her talent nor her dedication has gone unnoticed.", "Neither her talent or her dedication has gone unnoticed.", "Neither her talent or her dedication have gone unnoticed."]'::jsonb, 1, 3, '''Neither...nor'' (not ''neither...or''); verb agrees with the closer subject ''dedication'' (singular) -> ''has.'''),
('language', 'Choose the grammatically correct sentence.', NULL, '["To finish the project on time, extra shifts were worked by the team.", "To finish the project on time, the team worked extra shifts.", "The project, to finish on time, the team worked extra shifts.", "Extra shifts were worked to finish, the project on time, by the team."]'::jsonb, 1, 3, 'Infinitive phrase ''To finish the project on time'' must modify the subject ''the team'' — active voice avoids a dangling modifier.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["He speaks English fluent and writes it good.", "He speaks English fluently and writes it well.", "He speaks English fluently and writes it good.", "He speaks English fluent and writes it well."]'::jsonb, 1, 3, 'Adverbs ''fluently'' and ''well'' modify the verbs ''speaks'' and ''writes.'' Adjectives cannot modify verbs.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["The book that I was told about it is excellent.", "The book that I was told about is excellent.", "The book which I was told about it is excellent.", "The book about which I was told it is excellent."]'::jsonb, 1, 3, 'Relative clauses introduced by ''that'' do not repeat the object pronoun (''it''). ''The book that I was told about'' is complete.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["Irregardless of the outcome, we should try our best.", "Regardless of the outcome, we should try our best.", "Irregardless the outcome, we should try our best.", "Regardless the outcome, we should try our best."]'::jsonb, 1, 3, '''Irregardless'' is nonstandard English. The correct word is ''regardless.'''),
('language', 'Choose the grammatically correct sentence.', NULL, '["She bought less groceries than planned.", "She bought fewer groceries than planned.", "She bought less grocery than planned.", "She bought fewer grocery than planned."]'::jsonb, 1, 3, '''Fewer'' is used with countable nouns (groceries). ''Less'' is for uncountable quantities.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["You look as if you could use a rest.", "You look as though you could use a rest.", "Both A and B are correct.", "You look like you need a rest right now."]'::jsonb, 2, 3, '''As if'' and ''as though'' are interchangeable conjunctions introducing a subordinate clause — both are correct.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["The suspect insisted that he had laid in bed all morning.", "The suspect insisted that he had lain in bed all morning.", "The suspect insisted that he had lied in bed all morning.", "The suspect insisted that he had lay in bed all morning."]'::jsonb, 1, 3, 'Past participle of ''lie'' (to recline) is ''lain.'' ''Laid'' is the past tense/participle of ''lay'' (to place something).'),
('language', 'Choose the grammatically correct sentence.', NULL, '["I am anxious to start the new job next week.", "I am eager to start the new job next week.", "I am eager starting the new job next week.", "I am anxious starting the new job next week."]'::jsonb, 1, 3, '''Eager'' means enthusiastic anticipation (positive). ''Anxious'' implies worry or nervousness — not the intended meaning here.'),
('language', 'Choose the grammatically correct sentence.', NULL, '["The jury have reached their verdict.", "The jury has reached its verdict.", "The jury have reached its verdict.", "The jury has reached their verdict."]'::jsonb, 1, 3, 'Collective noun ''jury'' is singular in American English -> ''has'' and ''its.'''),
('language', 'Choose the grammatically correct sentence.', NULL, '["She is the smartest of all her siblings.", "She is the most smart of all her siblings.", "She is the smarter of all her siblings.", "She is more smarter than all her siblings."]'::jsonb, 0, 3, 'When comparing more than two, use the superlative ''-est.'' ''Most smart'' is a double superlative; ''smarter'' is comparative (two only).'),
('language', 'Which sentence uses the dash correctly?', NULL, '["She had only one dream \u2014 to become a doctor.", "She had \u2014 only one dream to become a doctor.", "She had only \u2014 one dream to become a doctor.", "She had only one \u2014 dream \u2014 to become a doctor."]'::jsonb, 0, 3, 'An em dash introduces an appositive or explanatory phrase at the end of a sentence.'),
('language', 'Which sentence uses the colon correctly?', NULL, '["He arrived late: and missed the opening act.", "The instructions were simple: read, write, and submit.", "The instructions: were simple to read write and submit.", "Read write and submit: were the simple instructions."]'::jsonb, 1, 3, 'A colon after a complete independent clause introduces a list or explanation. ''And'' after a colon is incorrect.'),
('language', 'Which sentence uses semicolons correctly in a complex list?', NULL, '["The guests were from Austin, Texas; Miami, Florida; and Portland, Oregon.", "The guests were from Austin Texas, Miami Florida, and Portland Oregon.", "The guests were from Austin, Texas, Miami, Florida, and Portland, Oregon.", "The guests were from Austin Texas; Miami Florida; Portland Oregon."]'::jsonb, 0, 3, 'When list items contain internal commas, use semicolons to separate the items clearly.'),
('language', 'Which sentence uses punctuation correctly with dialogue?', NULL, '["\\\"Where are you going?\\\" she asked.", "\\\"Where are you going\\\"? she asked.", "\\\"Where are you going?\\\" She asked.", "\\\"Where are you going\\\"? She asked."]'::jsonb, 0, 3, 'Question marks go inside the closing quotation marks; the dialogue tag (''she asked'') is lowercase and follows without a comma.'),
('language', 'Which sentence uses the hyphen correctly?', NULL, '["She is a well known scientist.", "She is a well-known scientist.", "She is a well-known-scientist.", "She is a well known-scientist."]'::jsonb, 1, 3, 'Hyphenate compound modifiers before a noun: ''well-known scientist.'' No hyphen when the modifier follows the noun.'),
('language', 'Which sentence uses punctuation correctly with a quotation?', NULL, '["He said, \\\"I will be there by noon\\\".", "He said, \\\"I will be there by noon.\\\"", "He said \\\"I will be there by noon.\\\"", "He said, ''I will be there by noon.''"]'::jsonb, 1, 3, 'In American English, periods go inside closing quotation marks. A comma before a direct quote and double quotes are both correct.'),
('language', 'Which sentence uses parentheses correctly?', NULL, '["The president (who was elected in 2020), announced a new policy.", "The policy (announced in January) took effect immediately.", "The policy, (announced in January) took effect immediately.", "The policy took effect (immediately, in January)."]'::jsonb, 1, 3, 'Parentheses enclose supplementary, nonessential information. No extra comma before or after parenthetical expressions.'),
('language', 'Which sentence uses the ellipsis correctly to show a pause?', NULL, '["She paused and said, \\\"I... I don''t know what to say.\\\"", "She paused and said, \\\"I . . I don''t know what to say.\\\"", "She paused and said, \\\"I..I don''t know what to say.\\\"", "She paused and said, \\\"I .... I don''t know what to say.\\\""]'::jsonb, 0, 3, 'An ellipsis within a sentence consists of three dots (...) used to indicate a pause or trailing thought.'),
('language', 'Which sentence best revises this fragment: ''Although the team practiced hard''?', NULL, '["Although the team practiced hard every day.", "Although the team practiced hard, they lost the championship.", "The team practiced hard, although.", "Although, the team practiced hard and lost."]'::jsonb, 1, 3, 'A subordinate clause beginning with ''although'' must be attached to an independent clause to form a complete sentence.'),
('language', 'Which sentence has faulty parallel structure?', NULL, '["She enjoys reading, writing, and to paint.", "She enjoys reading, writing, and painting.", "She enjoys to read, to write, and to paint.", "She enjoys reading books, writing stories, and painting portraits."]'::jsonb, 0, 3, 'Parallel structure: items in a series must match grammatically. ''To paint'' breaks the gerund (-ing) pattern.'),
('language', 'Which sentence has faulty parallel structure?', NULL, '["The manager told us to arrive early, work efficiently, and being professional.", "The manager told us to arrive early, work efficiently, and be professional.", "The manager told us to be early, efficient, and professional.", "The manager told us: arrive early, work efficiently, be professional."]'::jsonb, 0, 3, '''Being professional'' breaks the parallel infinitive structure (to arrive, to work, to be). Use ''be professional.'''),
('language', 'Which transition word best fills the blank? ''She studied all night; _____, she passed the exam.''', NULL, '["however", "consequently", "meanwhile", "nevertheless"]'::jsonb, 1, 3, '''Consequently'' signals cause-and-effect (studying -> passing). ''However'' and ''nevertheless'' signal contrast.'),
('language', 'Which sentence best corrects this run-on: ''I wanted to go to the game it was sold out''?', NULL, '["I wanted to go to the game, however it was sold out.", "I wanted to go to the game; it was sold out.", "I wanted to go, to the game, it was sold out.", "I wanted to go to the game and it was, sold out."]'::jsonb, 1, 3, 'A semicolon correctly joins two related independent clauses without a conjunction.'),
('language', 'Which revision of the following sentence is most concise? ''The reason why he left early was due to the fact that he was feeling sick.''', NULL, '["The reason he left early was because he felt sick.", "He left early because he was feeling sick.", "He left early due to the fact of his sickness.", "The reason why he left was that he was sick."]'::jsonb, 1, 3, 'Eliminating ''the reason why'' and ''due to the fact that'' and using simple past creates the most concise revision.'),
('language', 'Which sentence contains a misplaced modifier?', NULL, '["She only eats vegetables on Mondays.", "She eats only vegetables on Mondays.", "Only on Mondays does she eat vegetables.", "On Mondays, she eats only vegetables."]'::jsonb, 0, 3, '''Only'' modifies ''eats'' but should modify ''vegetables'' or ''Mondays.'' The misplacement changes the intended meaning.'),
('language', 'Which sentence best serves as a topic sentence for a paragraph about the dangers of social media?', NULL, '["Millions of teenagers use social media every day.", "Some people post vacation photos online.", "While social media connects people, its unchecked use poses significant risks to adolescent mental health.", "Social media companies make a lot of money from advertising."]'::jsonb, 2, 3, 'An effective topic sentence states a debatable, specific main idea the paragraph will develop.'),
('language', 'Which sentence best revises this wordy passage: ''At this point in time, it is absolutely necessary that all students make a decision about their future career plans''?', NULL, '["At this time, it is necessary for students to make a decision about careers.", "Now, all students must decide on a career.", "Students are required to make necessary decisions about careers at this point.", "It is now absolutely necessary that all students decide on a future career plan."]'::jsonb, 1, 3, '''Now, all students must decide on a career'' eliminates all redundancies while preserving the full meaning.'),
('language', 'Which sentence contains a comma splice?', NULL, '["She ran the race, and she won.", "She ran the race; she won.", "She ran the race, she won.", "She ran the race \u2014 and she won."]'::jsonb, 2, 3, 'A comma splice incorrectly joins two independent clauses with only a comma. Use a semicolon, conjunction, or period instead.');
insert into questions (section, prompt, passage, options, correct_index, difficulty, explanation) values
('reading', 'According to the passage, where do monarch butterflies spend the winter?', 'The monarch butterfly undertakes one of the longest migrations of any insect in North America. Each fall, millions of monarchs travel up to 3,000 miles from Canada and the United States to their wintering grounds in the mountains of central Mexico. Scientists are still studying how these butterflies navigate such vast distances using the sun as a compass.', '["Canada", "The United States", "The mountains of central Mexico", "South America"]'::jsonb, 2, 1, 'The passage directly states monarchs travel to ''wintering grounds in the mountains of central Mexico.'''),
('reading', 'How far can monarch butterflies travel during migration?', 'The monarch butterfly undertakes one of the longest migrations of any insect in North America. Each fall, millions of monarchs travel up to 3,000 miles from Canada and the United States to their wintering grounds in the mountains of central Mexico. Scientists are still studying how these butterflies navigate such vast distances using the sun as a compass.', '["Up to 1,000 miles", "Up to 2,000 miles", "Up to 3,000 miles", "Up to 4,000 miles"]'::jsonb, 2, 1, 'The passage states monarchs travel ''up to 3,000 miles.'''),
('reading', 'As used in the passage, ''navigate'' most nearly means:', 'The monarch butterfly undertakes one of the longest migrations of any insect in North America. Each fall, millions of monarchs travel up to 3,000 miles from Canada and the United States to their wintering grounds in the mountains of central Mexico. Scientists are still studying how these butterflies navigate such vast distances using the sun as a compass.', '["Fly fast", "Find one''s way", "Avoid danger", "Rest and recover"]'::jsonb, 1, 1, 'Navigate means to find one''s way through an area — used here to describe how butterflies find their route.'),
('reading', 'Before the railroad, approximately how long did it take to travel to California from the East Coast?', 'In 1869, the completion of the Transcontinental Railroad transformed American life. For the first time, passengers could travel from the East Coast to California in about a week, compared to the months required by wagon or ship. The railroad also accelerated westward settlement, as thousands of families relocated, and it created a national market by allowing goods to be shipped efficiently across the continent.', '["A few days", "About a week", "Several months", "About a year"]'::jsonb, 2, 2, 'The passage says wagon or ship travel took ''months'' compared to a week by rail.'),
('reading', 'Which conclusion is best supported by the passage?', 'In 1869, the completion of the Transcontinental Railroad transformed American life. For the first time, passengers could travel from the East Coast to California in about a week, compared to the months required by wagon or ship. The railroad also accelerated westward settlement, as thousands of families relocated, and it created a national market by allowing goods to be shipped efficiently across the continent.', '["The railroad made the wagon industry more profitable.", "The railroad had mostly negative effects on American life.", "The railroad connected economic and geographic parts of the nation.", "The railroad caused most Americans to move to California."]'::jsonb, 2, 2, 'The passage emphasizes both the geographic impact (faster travel, westward settlement) and the economic impact (national market), supporting that the railroad connected these aspects of the nation.'),
('reading', 'As used in the passage, ''accelerated'' most nearly means:', 'In 1869, the completion of the Transcontinental Railroad transformed American life. For the first time, passengers could travel from the East Coast to California in about a week, compared to the months required by wagon or ship. The railroad also accelerated westward settlement, as thousands of families relocated, and it created a national market by allowing goods to be shipped efficiently across the continent.', '["Slowed", "Stopped", "Sped up", "Reversed"]'::jsonb, 2, 2, 'Accelerated means increased in speed or rate — it sped up westward settlement.'),
('reading', 'What is the main idea of this passage?', 'In 1869, the completion of the Transcontinental Railroad transformed American life. For the first time, passengers could travel from the East Coast to California in about a week, compared to the months required by wagon or ship. The railroad also accelerated westward settlement, as thousands of families relocated, and it created a national market by allowing goods to be shipped efficiently across the continent.', '["The railroad was completed in 1869.", "Travel to California was once very slow.", "The Transcontinental Railroad greatly changed American society and economy.", "Thousands of families moved west after 1869."]'::jsonb, 2, 2, 'The passage opens with ''transformed American life'' and goes on to give several broad examples — the main idea is the railroad''s sweeping impact on the nation.'),
('reading', 'Based on the passage, which of the following best describes why advertisers use cognitive dissonance principles?', 'The term ''cognitive dissonance'' was introduced by psychologist Leon Festinger in 1957 to describe the discomfort people feel when they hold two conflicting beliefs simultaneously. Festinger proposed that this discomfort motivates individuals to reduce the inconsistency — either by changing one of their beliefs, acquiring new information that resolves the conflict, or minimizing the importance of one of the conflicting ideas. Advertisers and political campaigns have long understood this principle, designing messages that subtly shift audiences toward resolving dissonance in a preferred direction.', '["To confuse audiences so they buy more products.", "To guide audiences toward resolving internal conflicts in a way that favors the advertiser.", "To introduce new psychological research to the public.", "To ensure audiences feel comfortable with their existing beliefs."]'::jsonb, 1, 3, 'The passage states advertisers design messages to shift audiences toward resolving dissonance ''in a preferred direction'' — meaning the direction that benefits the advertiser.'),
('reading', 'As used in the passage, ''simultaneously'' most nearly means:', 'The term ''cognitive dissonance'' was introduced by psychologist Leon Festinger in 1957 to describe the discomfort people feel when they hold two conflicting beliefs simultaneously. Festinger proposed that this discomfort motivates individuals to reduce the inconsistency — either by changing one of their beliefs, acquiring new information that resolves the conflict, or minimizing the importance of one of the conflicting ideas. Advertisers and political campaigns have long understood this principle, designing messages that subtly shift audiences toward resolving dissonance in a preferred direction.', '["Eventually", "Repeatedly", "At the same time", "Gradually"]'::jsonb, 2, 3, 'Simultaneously means at the same time — used here to describe holding two conflicting beliefs at once.'),
('reading', 'The author most likely ends with the sentence about advertisers in order to:', 'The term ''cognitive dissonance'' was introduced by psychologist Leon Festinger in 1957 to describe the discomfort people feel when they hold two conflicting beliefs simultaneously. Festinger proposed that this discomfort motivates individuals to reduce the inconsistency — either by changing one of their beliefs, acquiring new information that resolves the conflict, or minimizing the importance of one of the conflicting ideas. Advertisers and political campaigns have long understood this principle, designing messages that subtly shift audiences toward resolving dissonance in a preferred direction.', '["Criticize the advertising industry.", "Show that the concept has practical, real-world applications beyond psychology.", "Prove that cognitive dissonance is harmful.", "Encourage readers to avoid advertisements."]'::jsonb, 1, 3, 'The final sentence extends the psychological concept into a real-world application, showing its practical relevance — not to criticize advertisers, but to broaden the concept''s scope.'),
('reading', 'What percentage of Earth''s surface do rain forests cover?', 'Rain forests cover about 6% of the Earth''s surface but are home to more than half of the world''s plant and animal species. They also play a critical role in regulating the Earth''s climate by absorbing large amounts of carbon dioxide.', '["25%", "50%", "6%", "12%"]'::jsonb, 2, 1, 'The passage directly states rain forests cover ''about 6% of the Earth''s surface.'''),
('reading', 'According to the passage, rain forests help regulate Earth''s climate by:', 'Rain forests cover about 6% of the Earth''s surface but are home to more than half of the world''s plant and animal species. They also play a critical role in regulating the Earth''s climate by absorbing large amounts of carbon dioxide.', '["Producing large amounts of oxygen only.", "Absorbing large amounts of carbon dioxide.", "Covering half the Earth''s surface.", "Housing millions of animal species."]'::jsonb, 1, 1, 'The passage states rain forests regulate climate ''by absorbing large amounts of carbon dioxide.'''),
('reading', 'Which conclusion is most strongly supported by the passage?', 'Rain forests cover about 6% of the Earth''s surface but are home to more than half of the world''s plant and animal species. They also play a critical role in regulating the Earth''s climate by absorbing large amounts of carbon dioxide.', '["Most species on Earth live in oceans.", "Destroying rain forests could have significant environmental consequences.", "Rain forests should be converted to farmland.", "Carbon dioxide is not harmful to the environment."]'::jsonb, 1, 2, 'Since rain forests house over half of Earth''s species and regulate climate, their destruction would logically cause major environmental harm — the passage strongly implies this.'),
('reading', 'As used in the passage, ''regulating'' most nearly means:', 'Rain forests cover about 6% of the Earth''s surface but are home to more than half of the world''s plant and animal species. They also play a critical role in regulating the Earth''s climate by absorbing large amounts of carbon dioxide.', '["Destroying", "Controlling", "Measuring", "Ignoring"]'::jsonb, 1, 2, 'Regulating means controlling or maintaining something within limits — here, controlling the Earth''s climate.'),
('reading', 'Which best describes the relationship between the two arguments presented in the passage?', 'Throughout history, societies have debated whether prosperity causes virtue or whether virtue causes prosperity. The ancient Greeks believed that character preceded wealth — that a just and disciplined person would naturally attract abundance. Later thinkers argued the reverse: that material security frees individuals to pursue moral development, since desperate people rarely have the luxury of ethical deliberation.', '["They agree that virtue and prosperity are unrelated.", "They offer opposing views on which comes first \u2014 virtue or prosperity.", "They both argue that ancient Greeks were correct.", "They suggest that only wealthy people can be virtuous."]'::jsonb, 1, 3, 'The Greeks argued virtue → prosperity; later thinkers argued prosperity → virtue. These are directly opposing positions on the causal relationship.'),
('reading', 'The phrase ''rarely have the luxury of ethical deliberation'' suggests that:', 'Throughout history, societies have debated whether prosperity causes virtue or whether virtue causes prosperity. The ancient Greeks believed that character preceded wealth — that a just and disciplined person would naturally attract abundance. Later thinkers argued the reverse: that material security frees individuals to pursue moral development, since desperate people rarely have the luxury of ethical deliberation.', '["Ethics is only for wealthy people to study.", "People in desperate circumstances may not have the time or resources to focus on moral choices.", "Ancient Greeks were wrong about virtue.", "Ethical deliberation is not important."]'::jsonb, 1, 3, 'The word ''luxury'' implies that ethical deliberation requires conditions of comfort and security that desperate people may not have — it''s a resource, not a character flaw.'),
('reading', 'What is the main idea of this passage?', 'Throughout history, societies have debated whether prosperity causes virtue or whether virtue causes prosperity. The ancient Greeks believed that character preceded wealth — that a just and disciplined person would naturally attract abundance. Later thinkers argued the reverse: that material security frees individuals to pursue moral development, since desperate people rarely have the luxury of ethical deliberation.', '["Ancient Greeks were more virtuous than modern people.", "Prosperity and virtue have a debated, complex relationship.", "Material wealth always leads to moral development.", "Ethical deliberation is only possible for the wealthy."]'::jsonb, 1, 2, 'The passage presents two competing historical views on the relationship between virtue and prosperity, framing it as a longstanding debate — the main idea.'),
('reading', 'As used in the passage, ''preceded'' most nearly means:', 'Throughout history, societies have debated whether prosperity causes virtue or whether virtue causes prosperity. The ancient Greeks believed that character preceded wealth — that a just and disciplined person would naturally attract abundance. Later thinkers argued the reverse: that material security frees individuals to pursue moral development, since desperate people rarely have the luxury of ethical deliberation.', '["Followed", "Came before", "Replaced", "Caused"]'::jsonb, 1, 1, 'Preceded means came before in time or order.'),
('reading', 'Before the printing press, why were books rare?', 'The printing press, invented by Johannes Gutenberg around 1440, revolutionized the spread of information in Europe. Before its invention, books were copied by hand, making them rare and expensive. The press allowed books to be produced quickly and cheaply, enabling literacy to spread and ideas to circulate more freely across regions and social classes.', '["Paper had not yet been invented.", "Books were copied by hand, making them slow and expensive to produce.", "Governments restricted book production.", "Most people did not know how to read."]'::jsonb, 1, 2, 'The passage states that before the press, ''books were copied by hand, making them rare and expensive.'''),
('reading', 'The passage implies that the printing press contributed most directly to:', 'The printing press, invented by Johannes Gutenberg around 1440, revolutionized the spread of information in Europe. Before its invention, books were copied by hand, making them rare and expensive. The press allowed books to be produced quickly and cheaply, enabling literacy to spread and ideas to circulate more freely across regions and social classes.', '["The invention of paper.", "A more informed and literate general population.", "Government censorship of ideas.", "A decrease in the quality of books."]'::jsonb, 1, 3, 'By making books cheap and accessible and enabling literacy to spread, the press would logically produce a more informed and literate population — the passage clearly implies this outcome.'),
('reading', 'Approximately when was the printing press invented?', 'The printing press, invented by Johannes Gutenberg around 1440, revolutionized the spread of information in Europe. Before its invention, books were copied by hand, making them rare and expensive. The press allowed books to be produced quickly and cheaply, enabling literacy to spread and ideas to circulate more freely across regions and social classes.', '["1340", "1440", "1540", "1640"]'::jsonb, 1, 1, 'The passage states Gutenberg invented the printing press ''around 1440.'''),
('reading', 'As used in the passage, ''circulate'' most nearly means:', 'The printing press, invented by Johannes Gutenberg around 1440, revolutionized the spread of information in Europe. Before its invention, books were copied by hand, making them rare and expensive. The press allowed books to be produced quickly and cheaply, enabling literacy to spread and ideas to circulate more freely across regions and social classes.', '["Stop", "Move around freely", "Be censored", "Be destroyed"]'::jsonb, 1, 2, 'Circulate means to move or flow freely through a system or area — ideas moving freely across regions.'),
('reading', 'Based on the passage, which group likely benefited MOST from the printing press?', 'The printing press, invented by Johannes Gutenberg around 1440, revolutionized the spread of information in Europe. Before its invention, books were copied by hand, making them rare and expensive. The press allowed books to be produced quickly and cheaply, enabling literacy to spread and ideas to circulate more freely across regions and social classes.', '["Wealthy nobles who could already afford hand-copied books.", "Church leaders who controlled book production.", "Common people who previously had little access to books.", "Scribes who copied books by hand."]'::jsonb, 2, 3, 'Since the press made books cheap and accessible ''across social classes,'' those who previously couldn''t afford expensive hand-copied books — common people — benefited most.'),
('reading', 'What is the main idea of this passage?', 'The printing press, invented by Johannes Gutenberg around 1440, revolutionized the spread of information in Europe. Before its invention, books were copied by hand, making them rare and expensive. The press allowed books to be produced quickly and cheaply, enabling literacy to spread and ideas to circulate more freely across regions and social classes.', '["Gutenberg was an important historical figure.", "Books were too expensive before 1440.", "The printing press transformed how information was shared in Europe.", "Literacy was rare in medieval Europe."]'::jsonb, 2, 2, 'The passage centers on how the printing press ''revolutionized the spread of information'' — its transformative impact on European society is the main idea.'),
('reading', 'The author includes the detail about books being ''copied by hand'' primarily to:', 'The printing press, invented by Johannes Gutenberg around 1440, revolutionized the spread of information in Europe. Before its invention, books were copied by hand, making them rare and expensive. The press allowed books to be produced quickly and cheaply, enabling literacy to spread and ideas to circulate more freely across regions and social classes.', '["Show that scribes were important workers.", "Provide contrast that highlights how significant the printing press was.", "Argue that handmade books were superior.", "Prove that literacy was impossible before Gutenberg."]'::jsonb, 1, 3, 'By showing how slow and expensive the old method was, the author creates contrast that makes the printing press''s impact more dramatic and easier to appreciate.')
