-- MATHEMATICS — 10 statistics questions + 8 geometry questions
-- ══════════════════════════════════════════════════════════════════════════════
-- Statistics Medium (5)
,('math', 'Four test scores are 72, 85, 90, and 78. The mean of all five scores is 82. What is the fifth score?', NULL, '["80", "83", "85", "88"]'::jsonb, 2, 2, 'Total needed = 5 × 82 = 410. Sum of four known scores = 72 + 85 + 90 + 78 = 325. Fifth score = 410 − 325 = 85.')
,('math', 'A data set has five values: 12, 14, 15, 16, and 93. Which statement is true?', NULL, '["The mean equals the median.", "The mean is greater than the median.", "The median is greater than the mean.", "The mean and median are both 15."]'::jsonb, 1, 2, 'Mean = (12+14+15+16+93) ÷ 5 = 150 ÷ 5 = 30. Median = 15 (middle value). The outlier 93 pulls the mean far above the median.')
,('math', 'A student scored 68 on a test worth 40% of the grade and 88 on a test worth 60% of the grade. What is the weighted average?', NULL, '["76", "78", "80", "82"]'::jsonb, 2, 2, 'Weighted average = (0.40 × 68) + (0.60 × 88) = 27.2 + 52.8 = 80.')
,('math', 'A set of five values has a range of 35. The largest value is 89. Four of the five values are 62, 71, 78, and 89. What must the fifth value be?', NULL, '["52", "54", "56", "58"]'::jsonb, 1, 2, 'Range = largest − smallest → smallest = 89 − 35 = 54. The fifth value must be 54.')
,('math', 'A data set contains: 3, 5, 7, 3, 9, 5, 3, 7, 5, 9. What is the mode?', NULL, '["3 only", "5 only", "3 and 5", "7 and 9"]'::jsonb, 2, 2, '3 appears 3 times and 5 appears 3 times — both tie for most frequent. A data set can have two modes (bimodal).')
-- Statistics Hard (5)
,('math', 'A class of 20 students has a mean test score of 74. One absent student later takes a makeup test. After adding this score, the class mean rises to 75. What did the student score on the makeup test?', NULL, '["85", "90", "95", "100"]'::jsonb, 2, 3, 'Original sum = 20 × 74 = 1480. New sum with 21 students = 21 × 75 = 1575. Makeup score = 1575 − 1480 = 95.')
,('math', 'Group A has 15 students with a mean score of 80. Group B has 10 students with a mean score of 70. What is the mean score of all 25 students combined?', NULL, '["74", "75", "76", "77"]'::jsonb, 2, 3, 'Total sum = (15 × 80) + (10 × 70) = 1200 + 700 = 1900. Combined mean = 1900 ÷ 25 = 76. (Note: you cannot simply average 80 and 70 because the groups are different sizes.)')
,('math', 'A data set of five values has a mean of 10, a median of 9, and a mode of 7. Which value must appear in the data set?', NULL, '["5", "7", "10", "15"]'::jsonb, 1, 3, 'Since 7 is the mode, it must appear more often than any other value, so 7 must be in the data set. The mean and median constrain the sum and middle value, but do not guarantee that 5, 10, or 15 are present.')
,('math', 'A teacher calculated the mean of 10 quiz scores and got 82. She then discovered she had recorded one score as 90 when it should have been 60. What is the correct mean?', NULL, '["77", "78", "79", "80"]'::jsonb, 2, 3, 'Original sum = 10 × 82 = 820. The error added 30 too much (90 instead of 60). Correct sum = 820 − 30 = 790. Correct mean = 790 ÷ 10 = 79.')
,('math', 'A data set of 8 values has a mean of 50. A ninth value is added and the mean rises to 52. How much greater than the original mean is the ninth value?', NULL, '["Above by 14", "Above by 16", "Above by 18", "Above by 20"]'::jsonb, 2, 3, 'Original sum = 8 × 50 = 400. New sum = 9 × 52 = 468. Ninth value = 468 − 400 = 68. Since 68 − 50 = 18, it is 18 above the original mean.')
-- Coordinate geometry Hard (4)
,('math', 'What is the distance between the points (1, 1) and (4, 5)?', NULL, '["3", "4", "5", "7"]'::jsonb, 2, 3, 'Distance = √((4−1)² + (5−1)²) = √(9 + 16) = √25 = 5.')
,('math', 'Point A is at (2, 6) and Point B is at (8, 2). What are the coordinates of the midpoint of segment AB?', NULL, '["(4, 4)", "(5, 4)", "(6, 4)", "(5, 5)"]'::jsonb, 1, 3, 'Midpoint = ((2+8)÷2, (6+2)÷2) = (10÷2, 8÷2) = (5, 4).')
,('math', 'A triangle has vertices at (0, 0), (6, 0), and (0, 8). What is the perimeter?', NULL, '["20", "22", "24", "26"]'::jsonb, 2, 3, 'The two legs are 6 and 8. Hypotenuse = √(6² + 8²) = √(36 + 64) = √100 = 10. Perimeter = 6 + 8 + 10 = 24.')
,('math', 'A circle has center (3, 3) and radius 5. Which of the following points lies INSIDE the circle?', NULL, '["(7, 3)", "(3, 9)", "(8, 3)", "(0, 7)"]'::jsonb, 0, 3, 'Distance from (3,3) to (7,3) = √((7−3)² + 0²) = √16 = 4 < 5, so it is inside. (3,9): d=6; (8,3): d=5 (on the circle); (0,7): d=√(9+16)=5 (on the circle). Only (7,3) is inside.')
-- Inscribed and composite shapes Hard (4)
,('math', 'A square has a diagonal of 10 units and is inscribed in a circle (all four corners touch the circle). What is the approximate area of the region inside the circle but outside the square? (Use π ≈ 3.14)', NULL, '["24.5", "26.5", "28.5", "30.5"]'::jsonb, 2, 3, 'Radius = diagonal ÷ 2 = 5. Circle area = 3.14 × 25 = 78.5. Square area = diagonal² ÷ 2 = 100 ÷ 2 = 50. Shaded region = 78.5 − 50 = 28.5.')
,('math', 'A circular ring is formed by two concentric circles. The outer radius is 8 and the inner radius is 5. What is the area of the ring? (Use π ≈ 3.14)', NULL, '["98.0", "110.0", "122.5", "150.7"]'::jsonb, 2, 3, 'Area of ring = π × (R² − r²) = 3.14 × (64 − 25) = 3.14 × 39 ≈ 122.5.')
,('math', 'A composite shape is made of a rectangle 12 units long and 6 units wide, with a semicircle attached to one of the shorter ends. The semicircle''s diameter equals the width of the rectangle. What is the total area? (Use π ≈ 3.14)', NULL, '["80.1", "83.1", "86.1", "90.1"]'::jsonb, 2, 3, 'Rectangle area = 12 × 6 = 72. Semicircle radius = 3. Semicircle area = (3.14 × 9) ÷ 2 = 14.13. Total ≈ 72 + 14.13 = 86.1.')
,('math', 'A circle of radius 4 is cut out of a square with side 10. What is the area of the remaining square? (Use π ≈ 3.14)', NULL, '["45.8", "47.8", "49.8", "51.8"]'::jsonb, 2, 3, 'Square area = 10² = 100. Circle area = 3.14 × 4² = 3.14 × 16 = 50.24. Remaining area = 100 − 50.24 = 49.76 ≈ 49.8.')
-- QUANTITATIVE — 1 additional Easy circle comparison (brings circles to 30% of shape comparisons)
,('quantitative', 'Shape A: a circle with radius 2. Shape B: a rectangle with length 6 and width 2. Which has the greater area? (Use π ≈ 3.14)', NULL, '["A is greater", "B is greater", "Equal", "Cannot determine"]'::jsonb, 0, 1, 'A: 3.14 × 2² = 3.14 × 4 ≈ 12.6. B: 6 × 2 = 12. A is greater by a small margin.')
